do
	local modules_folder = replicated_storage:FindFirstChild('Modules')
	if not modules_folder then
		return local_player:Kick('no modules folder found!')
	end

	local safe_require = function(module)
		if not module then
			return
		end

		local success, result = xpcall(require, function(err)
			return print('corescript', '[module error]', err)
		end, module)

		return success and result
	end

	for i=1, #modules do
		local module_name = modules[i]
		if not (module_name and type(module_name) == 'string') then
			continue
		end

		if not modules_folder:FindFirstChild(module_name) then
			return local_player:Kick(string_format('[FALLEN ULTIMATE] %* dont exist!', module_name))
		end

		local data = safe_require(modules_folder:FindFirstChild(module_name))

		if not data then
			return local_player:Kick(string_format('[FALLEN ULTIMATE %* failed to load!', module_name))
		end

		modules[module_name] = data
	end
end
