do --// connections functions
	Connections.New = LPH_NO_VIRTUALIZE(function(Name, Object, Signal)
		local Connection = {
			Name = Name,
			Object = Object,
			Signal = Signal,
		};

		Connections.Active[Name] = Connection
		return Connection
	end);

	Connections.Clear = LPH_NO_VIRTUALIZE(function(Name)
		local Connection = Connections.Active[Name]
		if Connection then 
			Connection.Signal:Disconnect();
			Connections.Active[Name] = nil;

			if not LPH_OBFUSCATED then 
				Utility.Print( ("Removing connection: %s, %s, %s"):format(Name, tostring(Object), tostring(Signal) ) )
			end;

			return true;
		end;

		return false;
	end);

	Connections.Check = LPH_NO_VIRTUALIZE(function()
		for Name, Connection in pairs(Connections.Active) do 
			if not Connection.Object and Connection.Signal then 
				Connections.Clear(Name);
			end;
		end;
	end);
end; 

