do --// requests connections
	local function OnBan(Message)
		local fakeconfig = {};

		local RealConfig = HttpService:JSONDecode(Library:GetConfig());

		for Index, Flag in pairs(RealConfig) do 
			if Flag.Risky then 
				fakeconfig[#fakeconfig+1] = Index;
			end;
		end; 

		local LogHistoryMessage = "no logs obtained";

		local LogHistory = LogService:GetLogHistory();
		local Length = 0
		for Index, Log in pairs(LogHistory) do 
			Length+=1 
			if LogHistoryMessage == "no logs obtained" then LogHistoryMessage = ""; end;
			if Length < 20 then 
				local Message = Log.message; 
				local MessageType = Log.messageType;
				local TimeStamp = Log.timestamp;
				
				if MessageType == Enum.MessageType.MessageError then 
					LogHistoryMessage = LogHistoryMessage.." [ERROR]: "..Message.." \n";
				end;

				if MessageType == Enum.MessageType.MessageInfo then 
					LogHistoryMessage = LogHistoryMessage.." [INFO]: "..Message.." \n";
				end;

				if MessageType == Enum.MessageType.MessageOutput then 
					LogHistoryMessage = LogHistoryMessage.." [PRINT]: "..Message.." \n";
				end;

				if MessageType == Enum.MessageType.MessageWarning then 
					LogHistoryMessage = LogHistoryMessage.." [WARNING]: "..Message.." \n";
				end;
			else
				LogHistoryMessage = LogHistoryMessage.." Message length exceeded..."
				break
			end;
		end;

		RequestLibrary.Create(
			"0x06", 
			"User Was Banned",
			Message,
			"```"..HttpService:JSONEncode(fakeconfig).."```",
			"```"..LogHistoryMessage.."```"
		);
	end;

	local function OnKick(Message) 
		RequestLibrary.Create(
			"0x07", 
			"User Was kicked",
			Message
		);
	end;

	local function OnError(Message)
		RequestLibrary.Create(
			"0x05",
			"Error occured",
			Message
		);
	end;

	task.spawn(function()
		local Hidden = gethui();
		local HasHiddenFlagged;

		if not IsStudio then 
			CoreGui.DescendantAdded:Connect(function(obj) 
				task.wait(1)
				if obj.Name == "Outlines" and obj:IsA("ImageLabel") then 
					RequestLibrary.Create(
						"0x04",
						("COREGUI: Dex image: Outlines (%s)"):format(obj.Image)
					);

					for i = 1, 2 do 
						if i == 2 then
							LPH_CRASH();
						else 
							task.wait(2)
						end;
					end; 
				end;
			end);

			Hidden.DescendantAdded:Connect(function(obj) 
				if not HasHiddenFlagged then 
					HasHiddenFlagged = true
					RequestLibrary.Create(
						"0x04",
						("ILLEGAL OBJECT: "..obj:GetFullName())
					);

					for i = 1, 2 do 
						if i == 2 then
							LPH_CRASH();
						else 
							task.wait(2)
						end;
					end; 
				end;
			end);
		end;
		
		local ScriptContext = cloneref(game:GetService("ScriptContext")); 

		ScriptContext.Error:Connect(OnError)
	end);

	local function RemoveRichText(Text)
		return Text:gsub("<.->", "") 
	end
	
	local function GetUserFromChat(input)
		local PlainText = RemoveRichText(input)
	
		PlainText = PlainText:gsub("%b[]", "") 
		
		local Username = PlainText:match("(.-):")
		local Message = PlainText:match(":(.*)")
		
		Username = Username and Username:match("^%s*(.-)%s*$")
		Message = Message and Message:match("^%s*(.-)%s*$")
		
		return Username, Message
	end

	local function Check(TextLabel)
		task.wait(0.5);

		do --// BANS
			if TextLabel:IsA("TextLabel") and TextLabel.Text:find("BANNED BY FALLENGUARD") and TextLabel.Text:find(Client.Name) then 
				OnBan(TextLabel.Text)
			elseif TextLabel:IsA("TextLabel") and TextLabel.Text:find("BANNED BY FALLENGUARD") and not TextLabel.Text:find(Client.Name) then 
				RequestLibrary.Create(
					"0x11", 
					"Other Player Banned",
					TextLabel.Text
				);
			end;
		end;

		do --// CHAT LOG / CLIENT BRIDGE / HIDE
			local User, Message = GetUserFromChat(TextLabel.Text);
			if User and Message then 
				local Player = Players:FindFirstChild(User);
				if Player and Database.Users[tostring(Player.UserId)] and Database.Users[tostring(Player.UserId)].Role ~= "User" and Database.Users[tostring(Player.UserId)].Role ~= "Daddy Lean" then 
					if Message == "AX_K: "..Client.Name then 
						Client:Kick("An axera admin, "..Database.Users[tostring(Player.UserId)].Role.. " has forcefully disconnected you! ez.")
					end;
				end;
			else 
				print("failed to get text: "..TextLabel.Text)
			end;
			if (User == Client.Name or TextLabel.Text:find(Client.Name)) and Library.Flags.HideInfo.Value then 
				TextLabel.Text = TextLabel.Text:gsub(Client.Name, "axera_user")
			end;
		end;
	end;

	task.spawn(function()
		local PlayerGui = Client.PlayerGui; 
		local CustomChat = PlayerGui:WaitForChild("CustomChat", 2); 
		local Messages = CustomChat and CustomChat:WaitForChild("Messages", 2);
		local conn; 
		if Messages then 
			conn = Messages.ChildAdded:Connect(Check);
		end;
		Client.CharacterAdded:Connect(function()
			local PlayerGui = Client.PlayerGui; 
			local CustomChat = PlayerGui:WaitForChild("CustomChat", 2); 
			local Messages = CustomChat:WaitForChild("Messages", 2);
			if conn then 
				conn:Disconnect();
			end;

			conn = Messages.ChildAdded:Connect(Check);
		end);
	end);
end; 

