	Utility.RunCharacterFunctions = LPH_JIT_MAX(function()
		for _, Function in getgc(false) do
			if type(Function) ~= 'function' or isexecutorclosure(Function) or iscclosure(Function) then
				continue
			end
		
			local Info = debug.getinfo(Function)
		
			local FunctionName = Info.name
			local FunctionSource = Info.source

			if FunctionName == 'PlayAnimation' and FunctionSource:find('ViewmodelController') then
				local OldPlayAnimation; OldPlayAnimation = hookfunction(Function, LPH_NO_UPVALUES(function(...)
					local Args = {...}
					if (Args[1] == 'WindupLoop' or Args[1] == 'Windup') and Library.Flags.DevSwing and Library.Flags.DevSwing.Value then
						OldPlayAnimation(unpack(Args))
						return {Length = 0.014} 
					end; 

					if Args[1] == "Use" and Library.Flags.FastHeal.Value then 
						Args[2] = 50
						OldPlayAnimation(unpack(Args));
						return {Length = 0.014} 
					end;

					-- if Args[1] == "Reload" and Library.Flags.FastReload.Value then  
					-- 	Args[2] = 50
					-- 	OldPlayAnimation(unpack(Args));
					-- 	return {Length = 0.014} 
					-- end;

					if (Args[1] == "Aim" or Args[1] == "AimHold" or Args[1] == "AimStop" or Args[1] == "AimStart") and Library.Flags.FastBow  and Library.Flags.FastBow.Value then  
						Args[2] = 50
						OldPlayAnimation(unpack(Args));
						return {Length = 0.014} 
					end;

					if Args[1] == "Bolt" and Library.Flags.InstantBolt and Library.Flags.InstantBolt.Value then 
						Args[2] = 50 
						OldPlayAnimation(unpack(Args));
						return {Length = 0.014} 
					end;

					return OldPlayAnimation(unpack(Args))
				end));
			end
		end;
	end);

	Utility.UpdateViewmodel = LPH_NO_VIRTUALIZE(function(Viewmodel)
		--pcall(function()
			repeat task.wait() until Viewmodel:FindFirstChild("Arms") and Viewmodel:FindFirstChild("Weapon")
			local Arms = Viewmodel:FindFirstChild("Arms");
			local Weapon = Viewmodel:FindFirstChild("Weapon");

			if Arms and Weapon then
				if Library.Flags.ViewmodelChams and Library.Flags.ViewmodelChams.Value then 
					 for Index, Part in next, Arms:GetDescendants() do 
						if Part:IsA("MeshPart") then
							if (Part.Name == "Sleeve" or Part.Name == "Armor") and Library.Flags.RemoveClothing and Library.Flags.RemoveClothing.Value then 
								Part.Transparency = 1; 
							end;
							
							if (Part.Name == "Sleeve" or Part.Name == "Armor")  and Library.Flags.ShirtChams and Library.Flags.ShirtChams.Value then 
								Part.TextureID = "rbxassetid://5843010904";
								Part.Material = Enum.Material["ForceField"];
								Part.Color = Library.Flags.ShirtColor.Color;
							end; 


							if (Part.Name == "Glove" or Part.Name == "Wrap") and Library.Flags.GloveChams and Library.Flags.GloveChams.Value then 
								Part.TextureID = "rbxassetid://5843010904";
								Part.Material = Enum.Material["ForceField"];
								Part.Color = Library.Flags.GloveColor.Color;
							end;

							if (Part.Name == "RightArm" or Part.Name == "LeftArm") and Library.Flags.ArmChams and Library.Flags.ArmChams.Value then 
								Part.TextureID = "rbxassetid://5843010904";
								Part.Material = Enum.Material["ForceField"];
								Part.Color = Library.Flags.ArmColor.Color;
							end;

						end;
					end;

					if Library.Flags.ItemChams.Value then
						for Index, Part in next, Weapon:GetDescendants() do 
							if Part and Part:IsA("MeshPart") then
								if Weapon:FindFirstChild("Attachments") then 
									if Part:IsDescendantOf(Weapon:FindFirstChild("Attachments")) then 
