										Part.Color = Library.Flags.VMItemColor.Color;
										Part.TextureID = "rbxassetid://5843010904";
									end;
								else 
									Part.Material = Enum.Material["ForceField"];
									Part.Color = Library.Flags.VMItemColor.Color;
									Part.TextureID = "rbxassetid://5843010904";
								end; 

							end;
