	Utility.GetDistanceFromCenter = LPH_NO_VIRTUALIZE(function(part)
		local position = part 
		if typeof(part) == "Instance" then 
			position = part.CFrame.p 
		end 
		local ScreenPosition, OnScreen = WTVP(Camera, position)
		if OnScreen then
			local Center = Vector2.new(Camera.ViewportSize.X / 2, Camera.ViewportSize.Y / 2)
			return (Center - Vector2.new(ScreenPosition.X, ScreenPosition.Y)).Magnitude
		end
		return math.huge 
	end);

	Utility.GetCurrentItem = LPH_NO_VIRTUALIZE(function()
		local Item = Workspace.VFX.VMs:GetChildren()[1];
	
		return Item
	end);

	Utility.GetBulletStats = LPH_NO_VIRTUALIZE(function(Item)
		if type(Item) ~= "string" then 
			Item = tostring(Item);
		end;

		local Modules = ReplicatedStorage:FindFirstChild("Modules")
		local ToolInfo = Modules and require(Modules:FindFirstChild("ToolInfo"));

		if ToolInfo and ToolInfo[Item] and rawget(ToolInfo[Item], "Bullet") then

			local Bullet = ToolInfo[Item].Bullet;
			local Speed = Bullet.Speed;
			local Gravity = Bullet.Gravity;
			local Range = Bullet.MaxRange;

			return Speed, Gravity, Range
		end;
		return 2100, 0.55, 650; -- Defaults to this if it fails
	end);

	Utility.GetThrowStats = LPH_NO_VIRTUALIZE(function(Item)
		if type(Item) ~= "string" then 
			Item = tostring(Item);
		end;

		local Modules = ReplicatedStorage:FindFirstChild("Modules")
		local ToolInfo = Modules and require(Modules:FindFirstChild("ToolInfo"));

		if ToolInfo and ToolInfo[Item] and rawget(ToolInfo[Item], "Weapon") and  rawget(ToolInfo[Item].Weapon, "ThrowInfo") then

			local Info = ToolInfo[Item].Weapon.ThrowInfo;
			local Speed = Info.Velocity;
			local Gravity = Info.GravityMult;
			local Range = 650

			return Speed, Gravity, Range
		end;
		return 65, 0.4, 650; -- Defaults to this if it fails
	end);

	Utility.IsPartVisible = LPH_NO_VIRTUALIZE(function(Destination, Origin)
		if not Destination then return false end;
		
		local Params = RaycastParams.new();
		Params.FilterType = Enum.RaycastFilterType.Blacklist; 
		Params.FilterDescendantsInstances = {Camera, Client.Character, Workspace:FindFirstChild("VFX")};
		
		local RaycastResult = Workspace:Raycast(Origin, (Destination.CFrame.p - Origin).Unit * 1100, Params);
		if RaycastResult and RaycastResult.Instance then 
			if RaycastResult.Instance:IsDescendantOf(Destination.Parent) then 
				return true;
			end;
		end;
		return false;
	end);

	Utility.FindVisiblePosition = LPH_NO_VIRTUALIZE(function(Origin, Destination)
		local OriginalDestination = Destination;

		if Utility.IsPartVisible(OriginalDestination, Origin) then
			return 
		end;
		
		if typeof(Destination) ~= "Vector3" then 
			Destination = Destination.CFrame.p;
		end;
		
		if typeof(Origin) ~= "Vector3" then 
			Origin = Origin.CFrame.p;
		end;
		
		local ManipulationOffsets = {
			(Camera.CFrame*CFrame.new(3, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(-3, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(-6, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(6, 0, 0)).Position; 

			(Camera.CFrame*CFrame.new(3, 2, 0)).Position; 
			(Camera.CFrame*CFrame.new(-3, 2, 0)).Position; 
			(Camera.CFrame*CFrame.new(-6, 2, 0)).Position; 
			(Camera.CFrame*CFrame.new(6, 2, 0)).Position;

			(Camera.CFrame*CFrame.new(4, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(-4, 2, 0)).Position; 
			(Camera.CFrame*CFrame.new(-4, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(4, 2, 0)).Position;

			(Camera.CFrame*CFrame.new(7, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(-7, 2, 0)).Position; 
			(Camera.CFrame*CFrame.new(-7, 0, 0)).Position; 
			(Camera.CFrame*CFrame.new(7, 2, 0)).Position;


			(Camera.CFrame*CFrame.new(0.2, 3.9, 0)).Position;

			(Camera.CFrame*CFrame.new(1.8, 4.1, 1)).Position;
			(Camera.CFrame*CFrame.new(2.1, 4.4, 1.1)).Position;

			(Camera.CFrame*CFrame.new(0.15, 5.2, 0.1)).Position;
			(Camera.CFrame*CFrame.new(-1.8, 5.4, -0.2)).Position;
			(Camera.CFrame*CFrame.new(-2.3, 6.35, -0.4)).Position;
			(Camera.CFrame*CFrame.new(0.1, 9.5, 0)).Position;
			(Camera.CFrame*CFrame.new(0.1, 8, 0)).Position;
			(Camera.CFrame*CFrame.new(0.1, 7.5, 0)).Position;

			--[[(Camera.CFrame*CFrame.new(0.15, -5.2, 0.1)).Position;
			(Camera.CFrame*CFrame.new(-1.8, -5.4, -0.2)).Position;
			(Camera.CFrame*CFrame.new(-2.3, -6.35, -0.4)).Position;
			(Camera.CFrame*CFrame.new(0.1, -9.5, 0)).Position;
			(Camera.CFrame*CFrame.new(0.1, -8, 0)).Position;
			(Camera.CFrame*CFrame.new(0.1, -7.5, 0)).Position;]]
		};

		for _, NewOrigin in next, ManipulationOffsets do
			if Utility.IsPartVisible(OriginalDestination, NewOrigin) then
				return NewOrigin;
			end;
		end;

	end);
end;

