do --// images initialization 
	LPH_NO_VIRTUALIZE(function()
		if not IsStudio then
			Images = {
				["Assist"] = "",
				["ColorV4"] = "",

				["VisualsV3"] = "",

				["ColorPicker"] = "",
				["DropdownArrow"] = "",
				["KeybindImage"] = "",
				["Misc"] = "",
			
				["Settings"] = "",
				["TransparencyImage"] = "",
				["Visuals"] = "",
				
				["Snowflake"] = "",


				["Chevron"] = "",
			
				["ChevronTransparent"] = "",
			
			
				["TriangleTransparent"] = "",
			
				["Triangle"] = "",
			};

			local s, e = pcall(function()
				for Name, ID in pairs(Images) do
					if not isfile("Axera/dependencies/images/"..Name..".png") then 
						writefile("Axera/dependencies/images/"..Name..".png", crypt.base64.decode(ID));
						Images[Name] = getcustomasset("Axera/dependencies/images/"..Name..".png")
					else 
						Images[Name] = getcustomasset("Axera/dependencies/images/"..Name..".png")
					end;
				end;
				
				local function Fetch(URL)       
					local Request = request({
						Url = URL,
						Headers = {
							["content-type"] = "application/json"
						},
						Method = "GET"
					});
				
					return Request.Body
				end;
				
				local function DownloadImage(Name, Body)
					writefile(Name, Body);
				
					return getcustomasset(Name)
				end;
				
				local LogoImage = Fetch("https://raw.githubusercontent.com/brokenfund/fonts/main/ultimateisud.png")
				LogoImage = DownloadImage("LOGO", LogoImage)
				Images["AxeraLogo"] = LogoImage;
			end);

			if not s and e then Utility.Print(tostring(e)) end;
		end;
	end)();
end;

do --// font initialization
	LPH_NO_VIRTUALIZE(function()
		Utility.Print("setting up fonts..")
		if setreadonly then --// Custom Font
			if isfile("Axera/dependencies/font/ESP-FONT.ttf") then 
				delfile("Axera/dependencies/font/ESP-FONT.ttf")
				delfile("Axera/dependencies/font/ESP_Font.font")
			end;

			Font = setreadonly(Font, false);
			function Font:Register(Name, Weight, Style, Asset)
				if not isfile(Asset.Id) then
					writefile("Axera/dependencies/font/"..Asset.Id, Asset.Font);
				end;

				local Data = {
					name = Name,
					faces = {{
						name = "Regular",
						weight = Weight,
						style = Style,
						assetId = getcustomasset("Axera/dependencies/font/"..Asset.Id);
					}}
				};
				
				writefile("Axera/dependencies/font/"..Name .. ".font", HttpService:JSONEncode(Data));
				return getcustomasset("Axera/dependencies/font/"..Name .. ".font");
			end;
			
			function Font:GetRegistry(Name)
				if isfile("Axera/dependencies/font/"..Name .. ".font") then
					return getcustomasset("Axera/dependencies/font/"..Name .. ".font");
				end;
			end;
			Font = setreadonly(Font, true)
		end;

		if setreadonly then

			Font:Register("ESP_Font", 200, "normal", {Id = "ESP-FONT.ttf", Font = crypt.base64.decode(
				""
			)});

			Font:Register("Verdana", 400, "normal", {Id = "Verdana-Font.ttf", Font = crypt.base64.decode(
				""
			)})

			Font:Register("FONT_2", 400, "normal", {Id = "FONT-2.ttf", Font = crypt.base64.decode(
			""
			)})

			--ESP.Font = Font.new(Font:GetRegistry("ESP_Font")) 
		end; 
		
		Utility.Print("finished creating fonts!", "Green")
	end)();
end;

