		function Indicators:NewIndicator(RealName, Text, Type)
			RealName = RealName or "New Indicator"
			Text = Text or "Feature";
			Type = Type or "Toggled"
			
			local NewIndicator = Instance.new("TextLabel")
			NewIndicator.Name = RealName
			NewIndicator.Parent = Indicators.KeybindsArea
			NewIndicator.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
			NewIndicator.BackgroundTransparency = 1.000
			NewIndicator.BorderColor3 = Color3.fromRGB(0, 0, 0)
			NewIndicator.BorderSizePixel = 0
			NewIndicator.Position = UDim2.new(-1, 0, 0, 21 * Indicators.CurrentPosition)
			NewIndicator.Size = UDim2.new(0, 200, 0, 21)
			NewIndicator.FontFace = Font.new("rbxasset://fonts/families/Ubuntu.json", Enum.FontWeight.Bold);
			NewIndicator.Text = Text .. string.format(" [ %s ]", Type)
			NewIndicator.TextColor3 = Color3.fromRGB(255, 255, 255)
			NewIndicator.TextSize = 14.000
			NewIndicator.TextXAlignment = Enum.TextXAlignment.Left
	
			Indicators.NewStroke(NewIndicator);
			Indicators.CurrentPosition += 1
			
			Library.Tween(NewIndicator, TweenInfo.new(0.1, Enum.EasingStyle.Linear, Enum.EasingDirection.In), {Position = UDim2.new(0, 0, 0, NewIndicator.Position.Y.Offset)})
			return NewIndicator
		end;
	
		function Indicators:RemoveIndicator(Name)
			if Indicators.KeybindsArea:FindFirstChild(Name) then
				local Indicator = Indicators.KeybindsArea:FindFirstChild(Name)
				local Tween = Library.Tween(
					Indicator,
					TweenInfo.new(0.1, Enum.EasingStyle.Linear, Enum.EasingDirection.Out),
					{Position = UDim2.new(-1, 0, 0, Indicator.Position.Y.Offset)}
				)
				Tween.Completed:Wait()
				Indicator:Destroy()
	
				local PositionIndex = 0
				for _, Object in ipairs(Indicators.KeybindsArea:GetChildren()) do
					if Object:IsA("TextLabel") then
						Library.Tween(Object, TweenInfo.new(0.1, Enum.EasingStyle.Linear, Enum.EasingDirection.Out), {Position = UDim2.new(0, 0, 0, 21 * PositionIndex)})
						PositionIndex = PositionIndex + 1
					end
				end
	
				Indicators.CurrentPosition = PositionIndex
			end
		end
	end)();

