			local function AddSnowflake()
				local Snowflake = Instance.new("ImageLabel")
				local Size = math.random(10, 20)
				Snowflake.Size = UDim2.new(0, Size, 0, Size)
				local StartY = -math.random()
				Snowflake.Position = UDim2.new(math.random(), 0, StartY, 0)  
				Snowflake.BackgroundTransparency = 1
				Snowflake.Image = Images["Snowflake"]
				Snowflake.Parent = Overlay
				local Color = math.random(0, 1);
				if Color == 1 then Snowflake.ImageColor3 = Library.Theme.Accent end

				local FallTween = Library.Tween(Snowflake, TweenInfo.new(FallSpeed, Enum.EasingStyle.Linear, Enum.EasingDirection.In), {Position = UDim2.new(Snowflake.Position.X.Scale, Snowflake.Position.X.Offset, 1.2, 0)})
				local FadeTween = Library.Tween(Snowflake, TweenInfo.new(FallSpeed + 4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageTransparency = 1})
				
				Library.Tween(Snowflake, TweenInfo.new(FallSpeed, Enum.EasingStyle.Bounce, Enum.EasingDirection.In), {Rotation = -360})
				FadeTween.Completed:Connect(function()
					Snowflake:Destroy()
				end)
			end

			local Conn;
			local function Snowflakes() 
				if tick() - SnowflakeTick > 1 then 
					SnowflakeTick = tick();
					for _ = 1, SnowflakeCount do
						AddSnowflake()
					end
				end;
			end;

			Conn = RunService.RenderStepped:Connect(function()
