		function Window:SetTab(Name) 
			task.spawn(function()
				task.spawn(function()
					Library.Tween(PageAnimator, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 0});
				end);

				task.wait(0.1);
				for TabName, Tab in next, Window.Tabs do 
					if TabName ~= Name then 
						Tab.IsOpen = false;
						Tab.Page.Visible = false;
						--Library.Tween(Tab.Page, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),  {Position = UDim2.new(0, 0, 1, 0)});
						Library.Tween(Tab.TabImage, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageColor3 = Library.Theme.TabOff});
						Library.Tween(Tab.TabText, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),  {TextColor3 = Library.Theme.TabOff});
					else 
						task.spawn(function()
							Tab.IsOpen = true;
							--Library.Tween(Tab.Page, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.In),  {Position = UDim2.new(0, 0, 0, 0)});
							Library.Tween(Tab.TabImage, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageColor3 = Library.Theme.Accent});
							Library.Tween(Tab.TabText, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),  {TextColor3 = Library.Theme.Accent});
						end);
					end;
				end;

				task.spawn(function()
					task.wait(0.1);
					Library.Tween(PageAnimator, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1});
					task.wait(0.1);
					Window.Tabs[Name].Page.Visible = true
				end);
			end);
		end; 

		function Window:AddTab(Data) 
			local Tab = {};
			Tab.Name = Data.Name and Data.Name:upper() or "TAB";
			Tab.Image = Data.Image or "http://www.roblox.com/asset/?id=135831094543411";
			Tab.IsOpen = false; 
			Tab.Sections = {};

			local TabButton = Instance.new("TextButton")
			local TabImage = Instance.new("ImageLabel")
			local TabText = Instance.new("TextLabel")
			local PageLayout = Instance.new("UIListLayout")

			local Page = Instance.new("Frame")

			do --// Elements 
				TabButton.Name = "TabButton"
				TabButton.Parent = Tabs
				TabButton.BackgroundColor3 = Library.Theme.BackgroundColor
				TabButton.BorderColor3 = Color3.fromRGB(0, 0, 0)
