				TabText.TextColor3 = Color3.fromRGB(110, 110, 110)
				TabText.TextSize = 14.000

				Page.Name = "Page"
				Page.Parent = Pages
				Page.BackgroundColor3 = Color3.fromRGB(255, 0, 4)
				Page.BackgroundTransparency = 1.000
				Page.BorderColor3 = Color3.fromRGB(0, 0, 0)
				Page.BorderSizePixel = 0
				Page.Size = UDim2.new(0, 715, 1, 0)
