				PageLayout.FillDirection = Enum.FillDirection.Horizontal
				PageLayout.SortOrder = Enum.SortOrder.LayoutOrder
				PageLayout.Padding = UDim.new(0, 13)

				Tab.Page = Page;
				Tab.TabImage = TabImage; 
				Tab.TabText = TabText;
			end; 

			do --// Connections 
				TabButton.MouseEnter:Connect(function()
					if Tab.IsOpen then return end; 
					
					Library.Tween(TabImage, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageColor3 = Color3.fromRGB(200, 200, 200)});
					Library.Tween(TabText, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),  {TextColor3 = Color3.fromRGB(200, 200, 200)});
				end);

				TabButton.MouseLeave:Connect(function()
					if Tab.IsOpen then return end;
					Library.Tween(TabImage, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageColor3 = Color3.fromRGB(110, 110, 110)});
					Library.Tween(TabText, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),  {TextColor3 = Color3.fromRGB(110, 110, 110)});
				end);

				TabButton.MouseButton1Down:Connect(function()
					Window:SetTab(Tab.Name);
				end);
			end;
			
