							local VALUE = {};

							function SearchFilter:Set(Value) 

								for Name, Table in pairs(SearchFilter.Options) do 
									Table.IsSelected = false;
								end;

								for Name, Table in pairs(SearchFilter.Options) do 
									if table.find(Value, Name) then 
										Table.IsSelected = true
										Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.Accent});
									else 
										Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
									end;
								end;


								SearchFilter.Value = Value;
								VALUE = Value;
								if Data.Callback then pcall(Data.Callback) end;
							end; 

							function SearchFilter:BeginSearching()
								for Index, Value in next, Items:GetChildren() do 
									if Value:IsA("GuiButton") then 
										local Text = string.lower(Value.Name);
										local Search = string.lower(SearchBox.Text);
										if SearchBox.Text == "" then 
											Value.Visible = true;
										else 
											if string.find(Text, Search) then 
												Value.Visible = true; 
											else 
												Value.Visible = false;
											end;    
										end;
									end;
								end;
							end;

							function SearchFilter:AddOption(Name, Category) 
								local OptionTable = {};
								OptionTable.IsSelected = false; 
								OptionTable.Name = Name; 
								OptionTable.Category = Category
								local Option = Instance.new("TextButton")
								local OptionName = Instance.new("TextLabel")
								local OptionCategory = Instance.new("TextLabel")
								
								Option.Name = Name
								Option.Parent = Items
								Option.BackgroundColor3 = Library.Theme.DropdownBackground
								Option.BorderColor3 = Color3.fromRGB(0, 0, 0)
								Option.BorderSizePixel = 0
								Option.Size = UDim2.new(1, 0, 0, 26)
								Option.AutoButtonColor = false
								Option.FontFace = Library.Font
								Option.Text = ""
								Option.TextColor3 = Color3.fromRGB(0, 0, 0)
								Option.TextSize = 14.000

								OptionTable.Button = Option 

								OptionName.Name = "OptionName"
								OptionName.Parent = Option
								OptionName.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								OptionName.BackgroundTransparency = 1.000
								OptionName.BorderColor3 = Color3.fromRGB(0, 0, 0)
								OptionName.BorderSizePixel = 0
								OptionName.Position = UDim2.new(0.0223602485, 0, 0, 0)
								OptionName.Size = UDim2.new(-0.0223602485, 200, 1, 0)
								OptionName.FontFace = Library.Font
								OptionName.Text = Name
								OptionName.TextColor3 = Color3.fromRGB(255, 255, 255)
								OptionName.TextSize = 14.000
								OptionName.TextXAlignment = Enum.TextXAlignment.Left

								OptionCategory.Name = "OptionCategory"
								OptionCategory.Parent = Option
								OptionCategory.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								OptionCategory.BackgroundTransparency = 1.000
								OptionCategory.BorderColor3 = Color3.fromRGB(0, 0, 0)
								OptionCategory.BorderSizePixel = 0
								OptionCategory.Position = UDim2.new(0.428571433, 0, 0, 0)
								OptionCategory.Size = UDim2.new(-0.0223602485, 200, 1, 0)
								OptionCategory.FontFace = Library.Font
								OptionCategory.Text = Category
								OptionCategory.TextColor3 = Color3.fromRGB(255, 255, 255)
								OptionCategory.TextSize = 14.000
								OptionCategory.TextXAlignment = Enum.TextXAlignment.Left;

								Option.MouseEnter:Connect(function()
									if OptionTable.IsSelected then return end;
									Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ButtonColor});
								end);

								Option.MouseLeave:Connect(function()
									if OptionTable.IsSelected then return end;
									Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
								end);

								Option.MouseButton1Down:Connect(function()
									OptionTable.IsSelected = not OptionTable.IsSelected
									if not OptionTable.IsSelected then 
										if table.find(VALUE, OptionTable.Name) then 
	
											for Index, Value in next, VALUE do 
												if Value == OptionTable.Name then 
													table.remove(VALUE, Index);
												end;
											end;
											--table.remove(VALUE, OptionTable.Name);
										end; 
									else 
										if not table.find(VALUE, OptionTable.Name) then 
											VALUE[#VALUE+1] = OptionTable.Name
										end;
									end; 
									SearchFilter:Set(VALUE)
								end);


								SearchFilter.Options[Name] = OptionTable
							end; 

							Button.MouseButton1Down:Connect(function()
							   -- pcall(ButtonTable.Callback);
								task.spawn(function()
									SearchFrame.Visible = not SearchFrame.Visible; 
									SearchFilter.Open = SearchFrame.Visible; 

									Library.Tween(Button, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.Accent})
									task.wait(0.1);
									Library.Tween(Button, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ButtonColor})
								end);
							end);

							SearchBox:GetPropertyChangedSignal("Text"):Connect(function()
								SearchFilter:BeginSearching();
							end);

							Button.MouseEnter:Connect(function()
								Library.Tween(Button, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Color3.fromRGB(49, 49, 49)})
							end);

							Button.MouseLeave:Connect(function()
								Library.Tween(Button, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ButtonColor})
							end);

							for Index, Value in next, Data.Options do 
								SearchFilter:AddOption(Value.Name, Value.Category) 
							end; 

							Library.Flags[SearchFilter.Flag] = SearchFilter; 

							return SearchFilter
						end;

