										Library.Tween(ToggleVisual, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {Position = UDim2.new(0, 16, 0, 3)})
										Library.Tween(ToggleVisual, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Color3.fromRGB(255, 255, 255)})
									else
										Library.Tween(ToggleButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ElementBackground});
										Library.Tween(ToggleVisual, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {Position = UDim2.new(0, 4, 0, 3)})
										Library.Tween(ToggleVisual, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Color3.fromRGB(124, 124, 124)})
										--{0, 4},{0, 3}
									end;

									value = Value
									if Data.Callback then pcall(Data.Callback) end;
								end;
							end;

							do --// Connections 
								ToggleButton.MouseButton1Down:Connect(function()
									if not Library.LoadingConfig and ToggleTable.Risky and not Main:FindFirstChild(ToggleTable.Name) then 
										if not value == true then 
											local ConfirmFrame = Instance.new("Frame");
											ConfirmFrame.Size = UDim2.new(1,0,1,0);
											ConfirmFrame.BackgroundColor3 = Color3.fromRGB(0,0,0);
