							end; 

							do --// Connections 
								DropdownButton.MouseButton1Down:Connect(function()
									DropdownTable.IsOpen = not DropdownTable.IsOpen;
									if DropdownTable.IsOpen then 
										Library.Tween(DropdownArrow, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Rotation = 180})
										Library.Tween(DropdownItems, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(1, 0, 0, 5 + #Data.Options * 22)})
									else
										Library.Tween(DropdownArrow, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Rotation = 0})
										Library.Tween(DropdownItems, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(1, 0, 0, 0)})
									end;
								end);
							end; 

							do --// Functions 
								function DropdownTable:Set(Value) 
									for Name, Table in pairs(DropdownTable.Options) do 
										
										if Name == Value then 
											Table.IsSelected = true; 
											Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.Accent});
										else 
											Table.IsSelected = false; 
											Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
										end;
									end;

									DropdownTable.Value = Value;
									if Data.Callback then pcall(Data.Callback) end;
									DropdownValue.Text = Value

								end; 
								function DropdownTable:AddOption(Name)
									local OptionTable = {};
									OptionTable.IsSelected = false; 
									OptionTable.Name = Name; 
									local Option = Instance.new("TextButton")
									Option.Name = "Option"
									Option.Parent = DropdownItems
									Option.BackgroundColor3 = Library.Theme.DropdownBackground
									Option.BorderColor3 = Color3.fromRGB(0, 0, 0)
									Option.BorderSizePixel = 0
									Option.Size = UDim2.new(0, 194, 0, 22)
									Option.AutoButtonColor = false
									Option.FontFace = Library.Font
									Option.Text = "       " ..Name
									Option.TextColor3 = Color3.fromRGB(255, 255, 255)
									Option.TextSize = 14.000
									Option.TextXAlignment = Enum.TextXAlignment.Left;

									Option.MouseEnter:Connect(function()
										if OptionTable.IsSelected then return end;
										Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ButtonColor});
									end);

									Option.MouseLeave:Connect(function()
										if OptionTable.IsSelected then return end;
										Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
									end);

									Option.MouseButton1Down:Connect(function()
										DropdownTable:Set(OptionTable.Name)
									end);

									OptionTable.Button = Option
									DropdownTable.Options[Name] = OptionTable;
									return OptionTable
								end;
							end;

							for Index, Value in pairs(Data.Options) do 
								DropdownTable:AddOption(Value);
							end;

							Library.Flags[DropdownTable.Flag] = DropdownTable
							if Data.Default then DropdownTable:Set(Data.Default) end;
							return DropdownTable
						end;

