								DropdownValue.TextXAlignment = Enum.TextXAlignment.Left
								
								DropdownCorner.CornerRadius = UDim.new(0, 2)
								DropdownCorner.Name = "DropdownCorner"
								DropdownCorner.Parent = DropdownButton
								
								DropdownArrow.Name = "DropdownArrow"
								DropdownArrow.Parent = DropdownButton
								DropdownArrow.AnchorPoint = Vector2.new(0, 0.5)
								DropdownArrow.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								DropdownArrow.BackgroundTransparency = 1.000
								DropdownArrow.BorderColor3 = Color3.fromRGB(0, 0, 0)
								DropdownArrow.BorderSizePixel = 0
								DropdownArrow.Position = UDim2.new(1, -20, 0.5, 0)
								DropdownArrow.Size = UDim2.new(0, 13, 0, 15)
								DropdownArrow.Image = Images["DropdownArrow"]
								DropdownArrow.ImageColor3 = Library.Theme.ElementOff
								
								DropdownItems.Name = "DropdownItems"
								DropdownItems.Parent = DropdownButton
								DropdownItems.BackgroundColor3 = Library.Theme.DropdownBackground
								DropdownItems.BorderColor3 = Color3.fromRGB(0, 0, 0)
								DropdownItems.BorderSizePixel = 0
								DropdownItems.ClipsDescendants = true
								DropdownItems.Position = UDim2.new(0, 0, 1, 0)
								DropdownItems.Size = UDim2.new(1, 0, 0, 0)
								
								DropdownLayout.Name = "DropdownLayout"
								DropdownLayout.Parent = DropdownItems
								DropdownLayout.SortOrder = Enum.SortOrder.LayoutOrder
							end; 

							do --// Connections 
								DropdownButton.MouseButton1Down:Connect(function()
									DropdownTable.IsOpen = not DropdownTable.IsOpen;
									if DropdownTable.IsOpen then 
										Library.Tween(DropdownArrow, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Rotation = 180})
										Library.Tween(DropdownItems, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(1, 0, 0, 5 + #Data.Options * 22)})
									else
										Library.Tween(DropdownArrow, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Rotation = 0})
										Library.Tween(DropdownItems, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(1, 0, 0, 0)})
									end;
								end);
							end; 

							do --// Functions 
								local VALUE = {};
								function DropdownTable:Set(Value) 

									for Name, Table in pairs(DropdownTable.Options) do 
										Table.IsSelected = false;
									end;
	
									for Name, Table in pairs(DropdownTable.Options) do 
										if table.find(Value, Name) then 
											Table.IsSelected = true
											Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.Accent});
										else 
											Library.Tween(Table.Button, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
										end;
									end;
	
	
									DropdownTable.Value = Value;
									VALUE = Value;
									DropdownValue.Text = table.concat(Value, ", ")
									if string.len(DropdownValue.Text) > 25 then
										DropdownValue.Text = string.sub(DropdownValue.Text, 1, 22) .. "..."
									end
									if Data.Callback then pcall(Data.Callback) end;
								end; 


								function DropdownTable:AddOption(Name)
									local OptionTable = {};
									OptionTable.IsSelected = false; 
									OptionTable.Name = Name; 
									local Option = Instance.new("TextButton")
									Option.Name = "Option"
									Option.Parent = DropdownItems
									Option.BackgroundColor3 = Library.Theme.DropdownBackground
									Option.BorderColor3 = Color3.fromRGB(0, 0, 0)
									Option.BorderSizePixel = 0
									Option.Size = UDim2.new(0, 194, 0, 22)
									Option.AutoButtonColor = false
									Option.FontFace = Library.Font
									Option.Text = "       " ..Name
									Option.TextColor3 = Color3.fromRGB(255, 255, 255)
									Option.TextSize = 14.000
									Option.TextXAlignment = Enum.TextXAlignment.Left;

									Option.MouseEnter:Connect(function()
										if OptionTable.IsSelected then return end;
										Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.ButtonColor});
									end);

									Option.MouseLeave:Connect(function()
										if OptionTable.IsSelected then return end;
										Library.Tween(Option, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundColor3 = Library.Theme.DropdownBackground});
									end);

									Option.MouseButton1Down:Connect(function()
										OptionTable.IsSelected = not OptionTable.IsSelected 

										if not OptionTable.IsSelected then 
											if table.find(VALUE, OptionTable.Name) then 

												for Index, Value in next, VALUE do 
													if Value == OptionTable.Name then 
														table.remove(VALUE, Index);
													end;
												end;
												--table.remove(VALUE, OptionTable.Name);
											end; 
										else 
											if not table.find(VALUE, OptionTable.Name) then 
												VALUE[#VALUE+1] = OptionTable.Name
											end;
										end; 
										DropdownTable:Set(VALUE)
									end);

									OptionTable.Button = Option
									DropdownTable.Options[Name] = OptionTable;
									return OptionTable
								end;
							end;

							for Index, Value in pairs(Data.Options) do 
								DropdownTable:AddOption(Value);
							end;

							Library.Flags[DropdownTable.Flag] = DropdownTable
							if Data.Default then DropdownTable:Set(Data.Default) end;
							return DropdownTable
						end;

						function SectionTable:Slider(Data)
							local SliderTable = {};
							SliderTable.Class = "Slider"
							SliderTable.Min = Data.Min or 0 
							SliderTable.Max = Data.Max or 10;
							SliderTable.Flag = Data.Flag or "Flag"
							SliderTable.Suffix = Data.Suffix or "";
							SliderTable.Name = Data.Name or "";
							SliderTable.Decimals = Data.Decimals or 0;
						
							local Slider = Instance.new("Frame")
							local SliderTitle = Instance.new("TextLabel")
							local SliderFrame = Instance.new("Frame")
							local SliderVisual = Instance.new("Frame")
							local SliderButton = Instance.new("TextButton")
							local UICorner = Instance.new("UICorner")
							local SliderValue = Instance.new("TextLabel");
						
							do --// Elements
								Slider.Name = "Slider"
