								Slider.Position = UDim2.new(0, 0, 0.251781464, 0)
								Slider.Size = UDim2.new(1, 0, 0.00475059403, 28)
						
								SliderTitle.Name = "SliderTitle"
								SliderTitle.Parent = Slider
								SliderTitle.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								SliderTitle.BackgroundTransparency = 1.000
								SliderTitle.BorderColor3 = Color3.fromRGB(0, 0, 0)
								SliderTitle.BorderSizePixel = 0
								SliderTitle.Size = UDim2.new(0, 194, 0, 13)
								SliderTitle.FontFace = Library.Font
								SliderTitle.Text = SliderTable.Name
								SliderTitle.TextColor3 = Color3.fromRGB(255, 255, 255)
								SliderTitle.TextSize = 14.000
								SliderTitle.TextXAlignment = Enum.TextXAlignment.Left
								SliderTitle.TextYAlignment = Enum.TextYAlignment.Top
						
								SliderFrame.Name = "SliderFrame"
								SliderFrame.Parent = Slider
								SliderFrame.BackgroundColor3 = Library.Theme.ElementBackground
								SliderFrame.BorderColor3 = Color3.fromRGB(0, 0, 0)
								SliderFrame.BorderSizePixel = 0
								SliderFrame.Position = UDim2.new(0, 0, 0, 25)
								SliderFrame.Size = UDim2.new(1, 0, 0, 5)
						
								SliderVisual.Name = "SliderVisual"
								SliderVisual.Parent = SliderFrame
								SliderVisual.BackgroundColor3 = Library.Theme.LightAccent
								SliderVisual.BorderColor3 = Color3.fromRGB(0, 0, 0)
								SliderVisual.BorderSizePixel = 0
								SliderVisual.Size = UDim2.new(0, 50, 1, 0)
						
								SliderButton.Name = "SliderButton"
								SliderButton.Parent = SliderFrame
								SliderButton.BackgroundColor3 = Library.Theme.LightAccent
								SliderButton.BorderColor3 = Color3.fromRGB(0, 0, 0)
								SliderButton.BorderSizePixel = 0
								SliderButton.Position = UDim2.new(0, 50, 0, -4)
								SliderButton.Size = UDim2.new(0, 14, 0, 14)
								SliderButton.AutoButtonColor = false
								SliderButton.FontFace = Library.Font
								SliderButton.Text = ""
								SliderButton.TextColor3 = Color3.fromRGB(0, 0, 0)
								SliderButton.TextSize = 14.000
						
								UICorner.CornerRadius = UDim.new(1, 0)
								UICorner.Parent = SliderButton
						
								SliderValue.Name = "SliderValue"
								SliderValue.Parent = Slider
								SliderValue.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								SliderValue.BackgroundTransparency = 1.000
								SliderValue.BorderColor3 = Color3.fromRGB(0, 0, 0)
								SliderValue.BorderSizePixel = 0
								SliderValue.Position = UDim2.new(0.670103073, 0, 0, 0)
								SliderValue.Size = UDim2.new(0, 63, 0, 13)
								SliderValue.FontFace = Library.Font
								SliderValue.TextColor3 = Color3.fromRGB(255, 255, 255)
								SliderValue.TextSize = 14.000
								SliderValue.TextXAlignment = Enum.TextXAlignment.Right
								SliderValue.TextYAlignment = Enum.TextYAlignment.Top
							end;

							do --// Functions
						
								function SliderTable:Set(Value)
									Value = math.clamp(Value, self.Min, self.Max)
									
									local formattedValue = string.format("%." .. self.Decimals .. "f", Value)
									self.Value = tonumber(formattedValue)
									
									local normalizedValue = (self.Value - self.Min) / (self.Max - self.Min)
									
									local visualTween = TweenService:Create(SliderVisual, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
										Size = UDim2.new(normalizedValue, 0, 1, 0)
									})
									local buttonTween = TweenService:Create(SliderButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
										Position = UDim2.new(normalizedValue, -SliderButton.Size.X.Offset / 2, 0, -4)
									})
								
									visualTween:Play()
									buttonTween:Play()
								
									SliderValue.Text = self.Value .. self.Suffix
								
									if Data.Callback then pcall(Data.Callback, self.Value) end
								end;

							end;
					
							do --// Connections 
								SliderButton.InputBegan:Connect(function(input)
									if input.UserInputType == Enum.UserInputType.MouseButton1 then
										local function UpdateSlider(inputPosition)
											local relativePosition = (inputPosition.X - SliderFrame.AbsolutePosition.X) / SliderFrame.AbsoluteSize.X
											local sliderValue = SliderTable.Min + relativePosition * (SliderTable.Max - SliderTable.Min)
											SliderTable:Set(sliderValue)
										end
							
										local connection
										connection = game:GetService("UserInputService").InputChanged:Connect(function(input)
											if input.UserInputType == Enum.UserInputType.MouseMovement then
												UpdateSlider(input.Position)
											end
										end)
							
										input.Changed:Connect(function()
											if input.UserInputState == Enum.UserInputState.End then
												connection:Disconnect()
											end
										end)
									end
								end);
							end;
							

							SliderTable:Set(SliderTable.Min)
							if Data.Default then SliderTable:Set(Data.Default) end;
							task.spawn(function()
								task.wait(0.1);
								if Data.Callback and Data.Default then pcall(Data.Callback) end;
							end);

							Library.Flags[SliderTable.Flag] = SliderTable;
							return SliderTable
						end;

