								KeybindDescription.TextSize = 14.000
								KeybindDescription.TextXAlignment = Enum.TextXAlignment.Left
								KeybindDescription.TextYAlignment = Enum.TextYAlignment.Top
								
								KeybindButton.Name = "KeybindButton"
								KeybindButton.Parent = Keybind
								KeybindButton.BackgroundColor3 = Library.Theme.ElementBackground
								KeybindButton.BorderColor3 = Color3.fromRGB(0, 0, 0)
								KeybindButton.BorderSizePixel = 0
								KeybindButton.Position = UDim2.new(0.60309279, 0, 0, 0)
								KeybindButton.Size = UDim2.new(0, 77, 0, 22)
								KeybindButton.AutoButtonColor = false
								KeybindButton.FontFace = Library.Font
								KeybindButton.Text = ""
								KeybindButton.TextColor3 = Color3.fromRGB(0, 0, 0)
								KeybindButton.TextSize = 14.000
								
