								KeybindCorner.Name = "KeybindCorner"
								KeybindCorner.Parent = KeybindButton
								
								KeybindValue.Name = "KeybindValue"
								KeybindValue.Parent = KeybindButton
								KeybindValue.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								KeybindValue.BackgroundTransparency = 1.000
								KeybindValue.BorderColor3 = Color3.fromRGB(0, 0, 0)
								KeybindValue.BorderSizePixel = 0
								KeybindValue.Position = UDim2.new(0, 35, 0, 0)
								KeybindValue.Size = UDim2.new(0, 40, 1, 0)
								KeybindValue.FontFace = Library.Font
								KeybindValue.Text = "none"
								KeybindValue.TextColor3 = Library.Theme.ElementOff
								KeybindValue.TextSize = 12.000
								KeybindValue.TextXAlignment = Enum.TextXAlignment.Left
								
								KeybindImage.Name = "KeybindImage"
								KeybindImage.Parent = KeybindButton
								KeybindImage.BackgroundColor3 = Color3.fromRGB(255, 255, 255)
								KeybindImage.BackgroundTransparency = 1.000
								KeybindImage.BorderColor3 = Color3.fromRGB(0, 0, 0)
								KeybindImage.BorderSizePixel = 0
								KeybindImage.Position = UDim2.new(0, 13, 0, 3)
								KeybindImage.Size = UDim2.new(0, 17, 0, 15)
								KeybindImage.Image = Images["KeybindImage"]
								KeybindImage.ImageColor3 = Color3.fromRGB(110, 110, 110)
							end;

							KeybindTable.IsSelectingKey = false 

							local abbreviations = {
								["MouseButton1"] = "MB1",
								["MouseButton2"] = "MB2",
								["MouseButton3"] = "MB3",
								["LeftShift"] = "LShift",
								["RightShift"] = "RShift",
								["LeftControl"] = "LCtrl",
								["RightControl"] = "RCtrl",
								["LeftAlt"] = "LAlt",
								["RightAlt"] = "RAlt",
								["Return"] = "Enter",
								["Backspace"] = "Back",
								["Space"] = "Space",
								["NumLock"] = "NumL",
								["LeftBracket"] = "[",
								["RightBracket"] = "]",
								["KeypadZero"] = "N0",
								["KeypadOne"] = "N1",
								["KeypadTwo"] = "N2",
								["KeypadThree"] = "N3",
								["KeypadFour"] = "N4",
								["KeypadFive"] = "N5",
								["KeypadSix"] = "N6",
								["KeypadSeven"] = "N7",
								["KeypadEight"] = "N8",
								["KeypadNine"] = "N9",
								["KeypadEnter"] = "KEnter",
								["KeypadMultiply"] = "N*",
								["KeypadPlus"] = "N+",
								["KeypadMinus"] = "N-",
								["KeypadPeriod"] = "N.",
								["Semicolon"] = ":",
								["KeypadDivide"] = "N/"
							}

							function KeybindTable:SetValue(newValue)
								self.Value = newValue
								pcall(KeybindTable.Callback)
							end
						
							function KeybindTable:Set(newKey)
								self.Key = newKey
								local keyText
						
								if tostring(newKey):find("KeyCode") then
									keyText = tostring(newKey):gsub("Enum.KeyCode.", "")
								else
									keyText = tostring(newKey):gsub("Enum.UserInputType.", "")
								end
						
								keyText = abbreviations[newKey] or (#keyText > 5 and abbreviations[keyText] or keyText)
						
								KeybindValue.Text = keyText
							end
						
							KeybindButton.MouseButton1Click:Connect(function()
								KeybindTable.IsSelectingKey = true
								KeybindValue.Text = "..."
								KeybindButton.Text = ""
								
								Library.Tween(KeybindButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundColor3 = Library.Theme.Accent})
								task.spawn(function()
									task.wait(0.2);
									Library.Tween(KeybindButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundColor3 = Library.Theme.ElementBackground})
								end);
								local inputConnection
								inputConnection = UserInputService.InputBegan:Connect(function(input)
									if KeybindTable.IsSelectingKey then
										if input.UserInputType == Enum.UserInputType.Keyboard or 
										   input.UserInputType == Enum.UserInputType.MouseButton1 or 
										   input.UserInputType == Enum.UserInputType.MouseButton2 then

											if input.UserInputType == Enum.UserInputType.Keyboard then 
												KeybindTable:Set(input.KeyCode)
											else 
												KeybindTable:Set(input.UserInputType)
											end;
											
											Indicators:RemoveIndicator(KeybindTable.Name)
											Delay(0.3, function()
												KeybindTable.IsSelectingKey = false
												inputConnection:Disconnect()
											end);
										end
									end
								end)
							end)
						
							UserInputService.InputBegan:Connect(function(input)
								if not KeybindTable.IsSelectingKey and not UserInputService:GetFocusedTextBox() then 
									if input.KeyCode == KeybindTable.Key or input.UserInputType == KeybindTable.Key then
										if KeybindTable.Mode == "Toggle" then
											KeybindTable:SetValue(not KeybindTable.Value)

											local Name = KeybindTable.Name:gsub(" key", "")
											Name = Name:gsub(" Key", "")
											if KeybindTable.Value then
												Indicators:RemoveIndicator(KeybindTable.Name)

												Indicators:NewIndicator(KeybindTable.Name, Name, KeybindValue.Text.. " - Toggled")
											else 
												Indicators:RemoveIndicator(KeybindTable.Name)
											end; 

										elseif KeybindTable.Mode == "Hold" then
											KeybindTable:SetValue(true)
											local Name = KeybindTable.Name:gsub(" key", "")
											Name = Name:gsub(" Key", "")
											if not Indicators.KeybindsArea:FindFirstChild(KeybindTable.Name) then
												Indicators:NewIndicator(KeybindTable.Name, Name, KeybindValue.Text.. " - Holding")
											end;
										end
									end; 
								end;
							end)

							UserInputService.InputEnded:Connect(function(input)
								if not KeybindTable.IsSelectingKey and not UserInputService:GetFocusedTextBox() then 
									if KeybindTable.Mode == "Hold" and (input.KeyCode == KeybindTable.Key or input.UserInputType == KeybindTable.Key) then
										KeybindTable:SetValue(false)
										local Name = KeybindTable.Name:gsub(" key", "")
										Name = Name:gsub(" Key", "")
										Indicators:RemoveIndicator(KeybindTable.Name)
									end
								end;
							end)

							if Data.Default then 
								KeybindTable:Set(Data.Default)
							end; 

							Library.Flags[KeybindTable.Flag] = KeybindTable

							return KeybindTable
						end;

