								function ColorpickerTable:ToHex(RGB)
									local Hexadecimal = "#"
	
									for Key, Value in pairs(RGB) do
										local Hex = ""
	
										while(Value > 0)do
											local index = math.fmod(Value, 16) + 1
											Value = math.floor(Value / 16)
											Hex = string.sub("0123456789ABCDEF", index, index) .. Hex			
										end
	
										if(string.len(Hex) == 0)then
											Hex = "00"
	
										elseif(string.len(Hex) == 1)then
											Hex = "0" .. Hex
										end
	
										Hexadecimal = Hexadecimal .. Hex
									end
	
									return Hexadecimal
								end;

								function ColorpickerTable:UpdateColor()
									local ColorX = (math.clamp(Mouse.X - ColorPicker.AbsolutePosition.X, 0, ColorPicker.AbsoluteSize.X)/ColorPicker.AbsoluteSize.X)
									local ColorY = (math.clamp(Mouse.Y - ColorPicker.AbsolutePosition.Y, 0, ColorPicker.AbsoluteSize.Y)/ColorPicker.AbsoluteSize.Y)
									Library.Tween(ColorPick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(ColorX, 0, ColorY, 0)})
									--ColorPick.Position = UDim2.new(ColorX, 0, ColorY, 0)
				
									Colors.s = 1 - ColorX
									Colors.v = 1 - ColorY
				
									ColorpickerButton.BackgroundColor3 = Color3.fromHSV(Colors.h, Colors.s, Colors.v)
									ColorpickerTable.Color = Color3.fromHSV(Colors.h, Colors.s, Colors.v);

									local R = math.floor((ColorpickerTable.Color.R * 255) * 255);
									local G = math.floor((ColorpickerTable.Color.G * 255) * 255);
									local B = math.floor((ColorpickerTable.Color.B * 255) * 255);
									

									local ToRGB = Color3.fromRGB(math.ceil(R), math.ceil(G), math.ceil(B));

									if Data.Callback then pcall(Data.Callback) end
								end;

								function ColorpickerTable:Set(new_Value, cb)
									local NColor, NTransparency = new_Value.Color, new_Value.Transparency;
				
									ColorpickerTable.Color = NColor; ColorpickerTable.Transparency = NTransparency;
	
									local duplicate = Color3.new(new_Value.Color.R, new_Value.Color.G, new_Value.Color.B);
									Colors.h, Colors.s, Colors.v = duplicate:ToHSV()
									Colors.h = math.clamp(Colors.h, 0, 1)
									Colors.s = math.clamp(Colors.s, 0, 1)
									Colors.v = math.clamp(Colors.v, 0, 1)

									local R = math.floor((ColorpickerTable.Color.R * 255) * 255);
									local G = math.floor((ColorpickerTable.Color.G * 255) * 255);
									local B = math.floor((ColorpickerTable.Color.B * 255) * 255);
				
									local ToRGB = Color3.fromRGB(math.ceil(R), math.ceil(G), math.ceil(B));
									Library.Tween(ColorPick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(1 - Colors.s, 0, 1 - Colors.v, 0)})

									if cb and Data.Callback then pcall(Data.Callback) end;
								   -- ColorPick.Position = UDim2.new(1 - Colors.s, 0, 1 - Colors.v, 0)
									ColorPicker.ImageColor3 = Color3.fromHSV(Colors.h, 1, 1)
									ColorpickerButton.BackgroundColor3 = Color3.fromHSV(Colors.h, Colors.s, Colors.v)
									Library.Tween(HuePick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(1 - Colors.h, 0, 0, 0)})
									--HuePick.Position = UDim2.new(1 - Colors.h, 0, 0, 0)
									if TransparencyImage then
										TransparencyImage.ImageColor3 = Color3.fromHSV(Colors.h, 1, 1)
										
										Library.Tween(TransparencyPick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(ColorpickerTable.Transparency, -1, 0, 0, 0)})

										--TransparencyPick.Position = UDim2.new(ColorpickerTable.Transparency, -1, 0, 0)
									end
									
									if Data.Callback then pcall(Data.Callback) end;
	
									if cb == nil or not cb then
				
									end
								end;

								function ColorpickerTable:UpdateHue()
									local y = math.clamp(Mouse.X - HuePicker.AbsolutePosition.X, 0, HuePicker.AbsoluteSize.X)
									Library.Tween(HuePick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(0, y, 0, 0)})
									--HuePick.Position = UDim2.new(0, y, 0, 0)
									local hue = y/HuePicker.AbsoluteSize.X
									Colors.h = 1-hue
									ColorPicker.ImageColor3 = Color3.fromHSV(Colors.h, 1, 1)
									ColorpickerButton.BackgroundColor3 = Color3.fromHSV(Colors.h, Colors.s, Colors.v)
									if TransparencyImage then
										TransparencyImage.ImageColor3 = Color3.fromHSV(Colors.h, 1, 1)
									end
									ColorpickerTable.Color = Color3.fromHSV(Colors.h, Colors.s, Colors.v)
									local R = math.floor((ColorpickerTable.Color.R * 255) * 255);
									local G = math.floor((ColorpickerTable.Color.G * 255) * 255);
									local B = math.floor((ColorpickerTable.Color.B * 255) * 255);
				
									local ToRGB = Color3.fromRGB(math.ceil(R), math.ceil(G), math.ceil(B));
								end;

								ColorpickerFrame.MouseEnter:Connect(function()
									IsInColor1 = true;
								end);
	
								ColorpickerFrame.MouseLeave:Connect(function()
									IsInColor1 = false;
								end);
	
								TransparencyPicker.MouseEnter:Connect(function()
									IsInTransparency = true;
								end);
	
								TransparencyPicker.MouseLeave:Connect(function()
									IsInTransparency = false;
								end);
	
								HuePicker.MouseEnter:Connect(function()
									IsInColor2 = true;
								end);
	
								HuePicker.MouseLeave:Connect(function()
									IsInColor2 = false;
								end);

								ColorpickerTable.ColorpickerFrame = ColorpickerFrame
		
	
								function ColorpickerTable:UpdateTransparency()
									local X = math.clamp(Mouse.X - TransparencyPicker.AbsolutePosition.X, 0, TransparencyPicker.AbsoluteSize.X)
									Library.Tween(TransparencyPick, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(0, X, 0, 0)})
									--TransparencyPick.Position = UDim2.new(0, X, 0, 0)
									local NewTransparency = X/TransparencyPicker.AbsoluteSize.X;
	
									ColorpickerTable.Transparency = NewTransparency;
									if Data.Callback then pcall(Data.Callback); end;
								end;
	
								TransparencyPicker.MouseButton1Down:Connect(function()
									ColorpickerTable:UpdateTransparency()
									local MoveConn = Mouse.Move:Connect(function()
										ColorpickerTable:UpdateTransparency()
									end)
									ReleaseConn = UserInputService.InputEnded:Connect(function(Input)
										if Input.UserInputType == Enum.UserInputType.MouseButton1 then
											ColorpickerTable:UpdateTransparency()
											MoveConn:Disconnect()
											ReleaseConn:Disconnect()
										end
									end)
	
								end);
	
								ColorpickerTable.Color = Color3.fromHSV(Colors.h, Colors.s, Colors.v)

								ColorPicker.MouseButton1Down:Connect(function()
									ColorpickerTable:UpdateColor()
									local MoveConnection = Mouse.Move:Connect(function()
										ColorpickerTable:UpdateColor()
									end)
									ReleaseConnection = UserInputService.InputEnded:Connect(function(Mouse)
										if Mouse.UserInputType == Enum.UserInputType.MouseButton1 then
											ColorpickerTable:UpdateColor()
											MoveConnection:Disconnect()
											ReleaseConnection:Disconnect()
										end
									end)
								end);

								HuePicker.MouseButton1Down:Connect(function()
									ColorpickerTable:UpdateHue()
									local MoveConnection = Mouse.Move:Connect(function()
										ColorpickerTable:UpdateHue()
									end)
									ReleaseConnection = UserInputService.InputEnded:Connect(function(Mouse)
										if Mouse.UserInputType == Enum.UserInputType.MouseButton1 then
											ColorpickerTable:UpdateHue()
											MoveConnection:Disconnect()
											ReleaseConnection:Disconnect()
										end
									end)
								end);
							end;

							if ColorpickerTable.Default then
								--ColorpickerTable.Transparency = ColorpickerTable.Default.Transparency
								ColorpickerTable:Set(ColorpickerTable.Default, true);

								
							end;

							Library.Flags[ColorpickerTable.Flag] = ColorpickerTable;
							return ColorpickerTable;
						end;

					end;

					Tab.Sections[Name] = SectionTable 
					return SectionTable
				end;
			end;

			Window.Tabs[Tab.Name] = Tab
			return Tab 
		end;

		Window.Name = Window.Name; 
		Library.Windows[Name] = Window;
		return Window 
	end);
end; 

