do --// notifications
	LPH_NO_VIRTUALIZE(function()
		local NotificationService = {}
		local notifications = {}
		local NotificationCount = 0
		local NotificationPosition = 33
		function NotificationService:NewNotification(message, duration)
			message = message or tostring(math.random())
			duration = duration or 3 

			local NotificationOutline = Instance.new("Frame")
			NotificationOutline.Name = "NotificationOutline"
			NotificationOutline.Parent = Library.CurrentScreenGui
			NotificationOutline.BackgroundColor3 = Library.Theme.OutlineColor
			NotificationOutline.BorderColor3 = Color3.fromRGB(0, 0, 0)
			NotificationOutline.Size = UDim2.new(0, 187, 0, 29)
			NotificationOutline.Position = UDim2.new(0, -50, 0, 30 + (NotificationPosition * (NotificationCount + 1)))
			NotificationOutline.BorderSizePixel = 1;

			local NotificationInline = Instance.new("Frame")
			NotificationInline.Name = "NotificationInline"
			NotificationInline.Parent = NotificationOutline
			NotificationInline.BackgroundColor3 = Library.Theme.BackgroundColor
			NotificationInline.BorderColor3 = Color3.fromRGB(0, 0, 0)
			NotificationInline.BorderSizePixel = 1;

			NotificationInline.Size = UDim2.new(1, -4, 1, -4)
			NotificationInline.Position = UDim2.new(0, 2, 0, 2)

			local NotificationText = Instance.new("TextLabel")
			NotificationText.Name = "NotificationText"
			NotificationText.Parent = NotificationInline
			NotificationText.BackgroundTransparency = 1
			NotificationText.Position = UDim2.new(0, 10, 0, 0)
			NotificationText.Size = UDim2.new(1, -20, 1, 0)
			NotificationText.FontFace = Library.Font
			NotificationText.Text = message
			NotificationText.TextColor3 = Color3.fromRGB(255, 255, 255)
			NotificationText.TextSize = 14
			
			local NotificationAccent = Instance.new("Frame")
			NotificationAccent.Name = "NotificationAccent"
			NotificationAccent.Parent = NotificationInline
			NotificationAccent.BackgroundColor3 = Library.Theme.LightAccent
			NotificationAccent.BorderColor3 = Color3.fromRGB(0, 0, 0)
			NotificationAccent.BorderSizePixel = 0
			NotificationAccent.Size = UDim2.new(0, 3, 0, 25)

			NotificationOutline.Size = UDim2.new(0, NotificationText.TextBounds.X + 27, 0, 29);

			NotificationCount +=1
			table.insert(notifications, NotificationOutline)
		
			NotificationService:SlideIn(NotificationOutline, duration)
		end
		
		function NotificationService:SlideIn(notification, duration)
			notification:TweenPosition(UDim2.new(0, 50, 0, 30 + (NotificationPosition * NotificationCount)), Enum.EasingDirection.Out, Enum.EasingStyle.Quad, 0.25, true, function()
				task.wait(duration)
				NotificationService:FadeOut(notification)
			end)
		end
		
		function NotificationService:FadeOut(notification)
			notification:SetAttribute("Tweening", true)
			task.spawn(function()
				task.wait();
				Library.Tween(notification, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
				Library.Tween(notification, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundColor3 = Library.Theme.Accent})
				for Index, Value in next, notification:GetDescendants() do 
					task.spawn(function()
						if Value.Name == "NotificationText" then 
							Library.Tween(Value, TweenInfo.new(0.1, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 1})
						else 
							Library.Tween(Value, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
						end;
					end);
				end;
			end);

			notification:TweenPosition(UDim2.new(0, -200, 0, notification.Position.Y.Offset), Enum.EasingDirection.Out, Enum.EasingStyle.Quad, 0.25, true, function()
				notification:Destroy()
				for i, notif in ipairs(notifications) do
					if notif == notification then 
						table.remove(notifications, i) 
						NotificationCount -=1 
					end; 
				end

				NotificationService:ReOrderNotifications()
			end)
		end
		
		function NotificationService:ReOrderNotifications()
			for i, notif in ipairs(notifications) do

				Library.Tween(notif, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Position = UDim2.new(0, 50, 0, 30 + (NotificationPosition * i))})
				--notif.Position = UDim2.new(0, 50, 0, NotificationPosition * i)
			end
		end;

		function Library:Notify(message, duration)
			return NotificationService:NewNotification(message, duration)
		end;
	end)();
end;

