	Library.UpdateInfoViewer = LPH_NO_VIRTUALIZE(function(TitleText, Text, VIP, HealthValue, Armor, WeaponTable) 
		--local s, e = pcall(function()
			local InfoViewer = Library.InfoViewer; 
			local InfoText = InfoViewer.InfoText 
			local Title = InfoViewer.Username;

			if VIP then 
				InfoViewer.VIPStatus.Text = "VIP";
				InfoViewer.VIPStatus.TextColor3 = Color3.fromRGB(243, 182, 12)
			else 
				InfoViewer.VIPStatus.Text = "Standard"
				InfoViewer.VIPStatus.TextColor3 = Color3.fromRGB(147, 163, 204)
			end;

			InfoViewer.Health.Text = HealthValue.."/100"
			InfoViewer.Headshot.Image = Headshots[TitleText];
			for Index, Name in next, Armor do 
				if Name == "None" then 
					InfoViewer[tostring(Index)].Visible = false 
				 else
					if ArmorImages[Name] then 
						InfoViewer[tostring(Index)].Image = ArmorImages[Name]
						InfoViewer[tostring(Index)].Visible = true 
					else 
						print("failed to find armor image for: "..Name)
					end;
				end;
			end;

			for i = 1, 4 do 
				if WeaponTable[i+1] and ArmorImages[WeaponTable[i+1]] then
					InfoViewer["A_"..tostring(i)].Visible = true;
					InfoViewer["A_"..tostring(i)].Image = ArmorImages[WeaponTable[i+1]];
				else 
					InfoViewer["A_"..tostring(i)].Visible = false;
				end;
			end; 

			if WeaponTable[1] and ArmorImages[WeaponTable[1]] then 
				InfoViewer["Weapon"].Visible = true 
				InfoViewer["Weapon"].Image = ArmorImages[WeaponTable[1]]
			else 
				InfoViewer["Weapon"].Visible = false; 
			end; 

			Title.Text = TitleText 
		--end); 
		--if not s and e then Utility.Print(e) end;
	end);
end; 

do --// modifications
	LPH_JIT_MAX(function()
		pcall(function()
			DeepCopy = function(Table)
				local Copy = {}
				for k, v in pairs(Table) do
					if type(v) == "table" then
						Copy[k] = DeepCopy(v)
					else
						Copy[k] = v
					end
				end
				return Copy
			end
		
			if ReplicatedStorage:FindFirstChild("Modules") and ReplicatedStorage.Modules:FindFirstChild("Items") then 
				local ToolModule = require(ReplicatedStorage:FindFirstChild("Modules").ToolInfo);
				local OldToolInfo = DeepCopy(ToolModule);

				function Modifications:ApplyNoShake(Value)
					for K, Weapon in next, ToolModule do 
						if rawget(Weapon, "Shake") and rawget(Weapon.Shake, "Speed") then 
							Weapon.Shake.Speed = Value and 0 or OldToolInfo[K].Shake.Speed;
						end;
					end
				end;

				function Modifications:ApplyBounce(Value)
					for K, Weapon in next, ToolModule do 
						if rawget(Weapon, "Melee") and rawget(Weapon.Melee, "BounceMult") then 
							Weapon.Melee.BounceMult = Value and 0 or OldToolInfo[K].Melee.BounceMult;
						end;
					end
				end;

				function Modifications:ApplyRange(Value)
					for K, Weapon in next, ToolModule do 
						if rawget(Weapon, "Melee") and rawget(Weapon.Melee, "MaxRange") then 
							Weapon.Melee.MaxRange = Value and 10 or OldToolInfo[K].Melee.MaxRange;
						end;
					end
				end;

				function Modifications:ApplyRecoil(Value)
					for K, Weapon in next, ToolModule do
						local s, e = pcall(function()
							if type(Weapon) == "table" then 
								if rawget(Weapon, "Recoil") and rawget(Weapon.Recoil, "Camera") then 
									if Value then
										Weapon.Recoil.Camera.Shake.X = {0, 0};
										Weapon.Recoil.Camera.Shake.Y = {0, 0};
			
										if Weapon.Shake then 
											Weapon.Shake.Speed = 0 
										end;
										local start = OldToolInfo[K].Recoil.Camera.RecoilStart
										Weapon.Recoil.Camera.RecoilStart = function(_)
											local Value, Val2 = start(_);
											return Value * (Library.Flags.RecoilPercent.Value / 100), Val2 * (Library.Flags.RecoilPercent.Value / 100)
										end; 
										
										local finish = OldToolInfo[K].Recoil.Camera.RecoilFinish
										Weapon.Recoil.Camera.RecoilFinish = function(_)
											local Value, Val2 = finish(_);
											return Value * (Library.Flags.RecoilPercent.Value / 100), Val2 * (Library.Flags.RecoilPercent.Value / 100)
										end;

									else
										Weapon.Recoil.Camera.Shake.X = OldToolInfo[K].Recoil.Camera.Shake.X;
										Weapon.Recoil.Camera.Shake.Y = OldToolInfo[K].Recoil.Camera.Shake.Y; 
										if Weapon.Shake then 
									--		Weapon.Shake.Speed = OldToolInfo[K].Weapon.Shake.Speed;
										end;

										Weapon.Recoil.Camera.RecoilStart = OldToolInfo[K].Recoil.Camera.RecoilStart; 
										Weapon.Recoil.Camera.RecoilFinish = OldToolInfo[K].Recoil.Camera.RecoilFinish; 
									end;
								end;
							end;
						end);

						if not s and e then Utility.Print(tostring(e)) end;
					end;
				end;

				function Modifications:ApplyVMRecoil(Value)
					for K, Weapon in next, ToolModule do
						local s, e = pcall(function()
							if type(Weapon) == "table" then 
								if rawget(Weapon, "Recoil") and rawget(Weapon.Recoil, "VM") then 
									if Value then
										Weapon.Recoil.VM.StartTime = 0
										Weapon.Recoil.VM.EndTime = 0
									else
										Weapon.Recoil.VM.StartTime = OldToolInfo[K].Recoil.VM.StartTime
										Weapon.Recoil.VM.EndTime = OldToolInfo[K].Recoil.VM.EndTime
									end;
								end;
							end;
						end);

						if not s and e then Utility.Print(tostring(e)) end;
					end;
				end;

				function Modifications:ApplyVMBobbing(Value)
					for K, Weapon in next, ToolModule do
						local s, e = pcall(function()
							if type(Weapon) == "table" then 
								if rawget(Weapon, "Weapon") and rawget(Weapon.Weapon, "VMMovementMults") then 
									if Value then
										Weapon.Weapon.VMMovementMults.Bobbing = 0;
										Weapon.Weapon.VMMovementMults.MouseSway = 0;
										Weapon.Weapon.VMMovementMults.SprintTilt = 0;
										Weapon.Weapon.VMMovementMults.SprintMoveDown = 0;
										Weapon.Weapon.VMMovementMults.SprintMoveBackward = 0;
									else
										Weapon.Weapon.VMMovementMults.Bobbing = OldToolInfo[K].Weapon.VMMovementMults.Bobbing
										Weapon.Weapon.VMMovementMults.MouseSway = OldToolInfo[K].Weapon.VMMovementMults.MouseSway;
										Weapon.Weapon.VMMovementMults.SprintTilt = OldToolInfo[K].Weapon.VMMovementMults.SprintTilt;
										Weapon.Weapon.VMMovementMults.SprintMoveDown = OldToolInfo[K].Weapon.VMMovementMults.SprintMoveDown;
										Weapon.Weapon.VMMovementMults.SprintMoveBackward = OldToolInfo[K].Weapon.VMMovementMults.SprintMoveBackward;
									end;
								end;
							end;
						end);

						if not s and e then Utility.Print(tostring(e)) end;
					end;
				end;
		
				function Modifications:ApplySpread(Value)
					for K, Weapon in next, ToolModule do
						pcall(function()
							if type(Weapon) == "table" then 
								if rawget(Weapon, "Spread") then 
									local OldSpread = OldToolInfo[K].Spread; do
										if rawget(Weapon.Spread, "Aiming") then 
											if Value then
												Weapon.Spread.Aiming.Idle = OldSpread.Aiming.Idle * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Aiming.ShootingExtra = OldSpread.Aiming.ShootingExtra * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Aiming.Moving = OldSpread.Aiming.Moving * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Aiming.Hide =  OldSpread.Aiming.Hide * (Library.Flags.SpreadPercent.Value / 100);
											else
												Weapon.Spread.Aiming.Idle = OldSpread.Aiming.Idle;
												Weapon.Spread.Aiming.ShootingExtra =  OldSpread.Aiming.ShootingExtra;
												Weapon.Spread.Aiming.Moving =  OldSpread.Aiming.Moving;
												Weapon.Spread.Aiming.Hide =  OldSpread.Aiming.Hide;
											end;
										end;
			
										if rawget(Weapon.Spread, "Shooting") then 
											if Value then 
												Weapon.Spread.Shooting.Idle = OldSpread.Shooting.Idle * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Shooting.ShootingExtra = OldSpread.Shooting.ShootingExtra * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Shooting.Moving = OldSpread.Shooting.Moving * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Shooting.Hide = OldSpread.Shooting.Hide * (Library.Flags.SpreadPercent.Value / 100);
											else 
												Weapon.Spread.Shooting.Idle = OldSpread.Shooting.Idle;
												Weapon.Spread.Shooting.ShootingExtra = OldSpread.Shooting.ShootingExtra;
												Weapon.Spread.Shooting.Moving = OldSpread.Shooting.Moving;
												Weapon.Spread.Shooting.Hide = OldSpread.Shooting.Hide;
											end;
										end;
			
										if rawget(Weapon.Spread, "Hip") then 
											if Value then 
												Weapon.Spread.Hip.Idle = OldSpread.Hip.Idle * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Hip.ShootingExtra = OldSpread.Hip.ShootingExtra * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Hip.Moving = OldSpread.Hip.Moving * (Library.Flags.SpreadPercent.Value / 100);
												Weapon.Spread.Hip.Hide = OldSpread.Hip.Hide * (Library.Flags.SpreadPercent.Value / 100);
											else 
												Weapon.Spread.Hip.Idle = OldSpread.Hip.Idle;
												Weapon.Spread.Hip.ShootingExtra = OldSpread.Hip.ShootingExtra;
												Weapon.Spread.Hip.Moving = OldSpread.Hip.Moving;
												Weapon.Spread.Hip.Hide = OldSpread.Hip.Hide;
											end;
										end;
									end;
								end;
							end;
						end);
					end;
				end;
		
				function Modifications:ApplyEquip(TOGGLE)
					for Index, Value in next, ToolModule do 
						pcall(function()
							if type(Value) == "table" and rawget(Value, "Weapon") then 
								local Old = OldToolInfo[Index].Weapon;
								if rawget(Value, "Weapon") then
									Value.Weapon.EquipAnimSpeed = TOGGLE and 6 or Old.EquipAnimSpeed;
								end;	
							end;
						end);
					end;    
				end;
		
				function Modifications:ApplyAim(TOGGLE)
					for Index, Value in next, ToolModule do 
						if type(Value) == "table" and rawget(Value, "Weapon") then 
							pcall(function()
								local Old = OldToolInfo[Index].Weapon;
								if rawget(Value.Weapon, "AimDownSpeed") then 
									Value.Weapon.AimDownSpeed.In = TOGGLE and 0 or Old.AimDownSpeed.In;
									Value.Weapon.AimDownSpeed.Out = TOGGLE and 0 or Old.AimDownSpeed.Out;
								end;
							end);
						end;    
					end;
				end;
				
				function Modifications:ApplyAuto(TOGGLE)
					for Index, Value in next, ToolModule do 
						if type(Value) == "table" and rawget(Value, "Weapon") then 
							pcall(function()
								local Old = OldToolInfo[Index].Weapon;
								if rawget(Value.Weapon, "RPM") then 
									Value.Weapon.Auto = TOGGLE and true or Old.Auto;
								end;
							end);
						end;    
					end;
				end;

				function Modifications:ApplyRPM(TOGGLE) 
					for Index, Value in next, ToolModule do 
						if type(Value) == "table" and rawget(Value, "Weapon") then 
							pcall(function()
								local Old = OldToolInfo[Index].Weapon;
								if rawget(Value.Weapon, "RPM") then 
									Value.Weapon.RPM = TOGGLE and (Old.RPM + (Old.RPM * 0.45)) or Old.RPM;
								end;
							end);
						end;    
					end;
				end;
		
				function Modifications:ApplySwing(TOGGLE)
					for Index, Value in next, ToolModule do 
						pcall(function()
							if type(Value) == "table" and rawget(Value, "Melee") and rawget(Value, "Weapon") then 
								if tostring(Index) ~= "Chainsaw" and tostring(Index) ~= "Mining Drill" then 
									Value.Weapon.Cooldown = TOGGLE and 0 or OldToolInfo[Index].Weapon.Cooldown
								end;
							end;
						end);
					end;
				end; 

				function Modifications:ApplyFastMed(TOGGLE)
					for Index, Value in next, ToolModule do 
						pcall(function()
							if type(Value) == "table" and rawget(Value, "Weapon") and rawget(Value.Weapon, "HealthItem") then 
								if tostring(Index) ~= "Chainsaw" and tostring(Index) ~= "Mining Drill" then 
									Value.Weapon.Cooldown = TOGGLE and 0.14 or OldToolInfo[Index].Weapon.Cooldown
								end;
							end;
						end);
					end;
				end; 

				getgenv().GMV = true
				Library:Notify("Gunmods bypass ran successfully!", 10)
			end;
		end);
	end)();
end;

do --// visuals 
	Utility.Print("setting up visuals module..")

	do --// FOV Circle
		local ScreenUI = Instance.new("ScreenGui");
		ScreenUI.Parent = setreadonly and CoreGui or Client.PlayerGui

		local FOVCircle = Instance.new("Frame"); 
		local FOVInline = Instance.new("Frame");
		local FOVInlineCorner = Instance.new("UICorner");
		local CenterScreen = Camera.ViewportSize / 2; 
		local Corner = Instance.new("UICorner"); 
		local Stroke = Instance.new("UIStroke"); 
			
		local FOVOutline = Instance.new("Frame");
		local OutlineCorner = Instance.new("UICorner");
		local OutlineStroke = Instance.new("UIStroke");

		--// Properties (FOV);
		do 
				ScreenUI.IgnoreGuiInset = true;

				FOVCircle.Parent = FOVOutline
				FOVCircle.BackgroundTransparency = 1
				FOVCircle.ZIndex = 9999
				FOVCircle.BackgroundColor3 = Color3.new(1,1,1)
				FOVCircle.Position = UDim2.new(0, -1, 0, -1)
				FOVCircle.Size = UDim2.new(1, 2, 1, 2)
				FOVCircle.Visible = true;

				FOVInline.Parent = FOVCircle; 
				FOVInline.Size = UDim2.new(1, -2, 1, -2);
				FOVInline.Position = UDim2.new(0, 1, 0, 1);

				FOVInlineCorner.Parent = FOVInline 
				FOVInlineCorner.CornerRadius = UDim.new(1, 0);

				FOVOutline.AnchorPoint = Vector2.new(0.5, 0.5)
				
				FOVOutline.Position = UDim2.new(0, CenterScreen.X, 0, CenterScreen.Y);
				FOVOutline.BackgroundTransparency = 1 
				FOVOutline.Parent = ScreenUI 
				FOVOutline.ZIndex = 9999 
				FOVOutline.Size = UDim2.new(0, 500, 0, 500)

				FOVOutline.Visible = false

				Corner.Parent = FOVCircle
				Corner.CornerRadius = UDim.new(1, 0)

				Stroke.Parent = FOVCircle
				Stroke.Color = Color3.new(1,1,1)
				Stroke.Thickness = 3

				--OutlineStroke.LineJoinMode = Enum.LineJoinMode.Miter
				OutlineStroke.Thickness = 5
				OutlineStroke.Color = Color3.new(0,0,0)
				OutlineStroke.Name = "OutlineStroke"
				OutlineStroke.Parent = FOVOutline 

				OutlineCorner.Parent = FOVOutline
				OutlineCorner.CornerRadius = UDim.new(1, 0)

		end;

		Visuals.FOVInline = FOVInline;
		Visuals.FOVOutline = FOVOutline
		Visuals.FOVCircle = FOVCircle 
		Visuals.FOVStroke = Stroke

		if not IsStudio then 
				Visuals.TargetLine = Drawing.new("Line");
				Visuals.TargetLine.Thickness = 1.5;
				Visuals.TargetLine.Visible = false;
		end;
	end;

		
	Visuals.RotateLine = LPH_NO_VIRTUALIZE(function(Object, Thickness, From, To)
		Object.Thickness = Thickness + 0.5
		Object.From = From 
		Object.To = To;
	end);

	Visuals.FloorVector = LPH_NO_VIRTUALIZE(function(Vector)
		if typeof(Vector) == "Vector2" then 
			return Vector2.new(math.floor(Vector.X), math.floor(Vector.Y));
		else 
			return Vector3.new(math.floor(Vector.X), math.floor(Vector.Y), math.floor(Vector.Z));
		end;
	end);

	Visuals.GetBoundingBox = LPH_NO_VIRTUALIZE(function(model, orientation)
		if typeof(model) == "Instance" then
			model = model:GetChildren()
		end

		if not orientation then
			orientation = CFrame.new()
		end
		local abs = math.abs
		local inf = math.huge
		
		local minx, miny, minz = inf, inf, inf
		local maxx, maxy, maxz = -inf, -inf, -inf
			
		for _, obj in pairs(model) do
			if obj:IsA("BasePart") then
				local cf = obj.CFrame
				cf = orientation:toObjectSpace(cf)
				local size = obj.Size
				local sx, sy, sz = size.X, size.Y, size.Z
		
				local x, y, z, R00, R01, R02, R10, R11, R12, R20, R21, R22 = cf:components()
		
				local wsx = 0.5 * (abs(R00) * sx + abs(R01) * sy + abs(R02) * sz)
				local wsy = 0.5 * (abs(R10) * sx + abs(R11) * sy + abs(R12) * sz)
				local wsz = 0.5 * (abs(R20) * sx + abs(R21) * sy + abs(R22) * sz)
		
				if minx > x - wsx then
						minx = x - wsx
				end
				if miny > y - wsy then
						miny = y - wsy
				end
				if minz > z - wsz then
						minz = z - wsz
				end
		
				if maxx < x + wsx then
						maxx = x + wsx
				end
				if maxy < y + wsy then
						maxy = y + wsy
				end
				if maxz < z + wsz then
						maxz = z + wsz
				end
			end
		end
		
		local omin, omax = Vector3.new(minx, miny, minz), Vector3.new(maxx, maxy, maxz)
		local omiddle = (omax+omin)/2
		local wCf = orientation - orientation.p + orientation:pointToWorldSpace(omiddle)
		local size = (omax-omin)
		return wCf, size
	end);

	Visuals.IsPartVisible = LPH_NO_VIRTUALIZE(function(Part) 
		if not Part then return nil end; 

		local Origin = Camera.CFrame.p; 
		local Direction = (Part.CFrame.p - Origin).Unit * (Part.CFrame.p - Origin).Magnitude;

		local Params = RaycastParams.new();
		Params.FilterType = Enum.RaycastFilterType.Blacklist; 

		if game.PlaceId == 8392422325 then 
			Params.FilterDescendantsInstances = {Camera, Client.Character, Workspace.Ignore, Workspace.Misc};
		else 
			Params.FilterDescendantsInstances = {Camera, Client.Character, Workspace:FindFirstChild("VFX")};
		end;

		local RayResult = Workspace:Raycast(Origin, Direction, Params);

		if RayResult and RayResult.Instance and RayResult.Instance:IsDescendantOf(Part.Parent) then 
			return true 
		end;

		return nil;
	end);
	Utility.Print("finished creating visuals module!", "Green")
end;

