		function Entities.Functions:New(Data)
			local IsPlayer = Data.IsPlayer;
			local Character = Data.Character or nil;
			local Object  = Data.Object;
			local Name = Data.Name;
			local DisplayName = Data.DisplayName or Name;

			local Constructor = setmetatable({
				IsPlayer = IsPlayer,
				Character = Character,
				LastVisCheck = tick(),
				Object = Object,
				Name = Name,
				DisplayName = DisplayName;
				Components = ESP:CreateComponents();
				LastUpdate = tick();
				Boss = Data.Boss; 
			}, Entities.Functions);

			Entities.List[Object] = Constructor;

			return Entities.List[Object]
		end;
		
		function Items.Functions:New(Data)
			local Object = {};
			Object.Object = Data.Object
			Object.Root = Data.Root;
			Object.Name = Data.Name;
			Object.GetCustomName = Data.GetCustomName;
			Object.CustomCheck = Data.CustomCheck;
			Object.GetRoot = Data.GetRoot;
			Object.Class = Data.Class;
			if not Data.CreateLater then 
				Object.Components = ESP:CreateItemComponents();
			end; 

			Object.ColorListener = Data.ColorListener;
			Object.LastUpdate = tick();

			local Constructor = setmetatable(Object, Items.Functions);
			Items.List[Data.Object] = Constructor
			return Constructor;
		end;

		do --// Misc
			ESP.ServerPosition = ESP:CreateItemComponents();
		end;

		do --// Flags 
			Entities.Functions.Flags = {};
			function Entities.Functions:AddFlag(Arguments)
				local Data = {
					Text = Arguments.Text;
					Flag = Arguments.Flag;
					Name = Arguments.Name;
					Allow = Arguments.Allow;
				};

				Entities.Functions.Flags[Data.Name] = Data;
			end;
		end;

		do --// Get Stats
			function Entities.Functions:GetCharacter()
				if self.IsPlayer then 
					return self.Object.Character 
				end;

				return self.Object;
			end;

			function Entities.Functions:GetTeam()
				return self.Object.Team
			end;

			function Entities.Functions:GetRoot()
			if self.Character then return self.Character:FindFirstChild("HumanoidRootPart") end;
				return nil;
			end;

			function Entities.Functions:GetHealth()
				local Humanoid = self.Character and self.Character:FindFirstChildOfClass("Humanoid");

				if Humanoid then 
					if self.IsPlayer or not self.IsPlayer then

						if self.Object.Name == "BTR" then 
							return self.Object:GetAttribute("Health"), self.Object:GetAttribute("MaxHealth")
						end
						local Health = Humanoid.Health 
						if Health <= 0 then 
							Health = 0.1;
						end;

						return Health, Humanoid.MaxHealth;
					end;
				end;

				return 0, 100
			end;

			function Entities.Functions:GetWeapon()
				local Weapon, WeaponName = nil, "None";

				if self.Object.Name == "BTR" then 
					return self.Object, "BTR Cannon"
				end; 

				if self.Character and self.IsPlayer then 
					for Index, Value in ipairs(self.Character:GetChildren()) do 
						if Value:IsA("Model") and Weapons[Value.Name] then
							Weapon = Value;
							WeaponName = Value.Name;
							break;
						end;
					end;
				end;

				if not self.IsPlayer then 
					for Index, Value in ipairs(self.Object:GetChildren()) do 
						if Value:IsA("Model") and Value.Name == "Default" and (Value:FindFirstChild("Receiver") or Value:FindFirstChild("Reciever")) then
							local Receiver = Value:FindFirstChild("Receiver") or Value:FindFirstChild("Reciever")
							Weapon = Value;
							WeaponName = "Military M4A1"
							if Receiver.TextureID == "rbxassetid://13633713305" and Receiver.MeshId == "rbxassetid://13633713096" then 
								WeaponName = "Salvaged AK74u"
								break;
							end; 

							if Receiver.TextureID == "rbxassetid://15346209825" and Receiver.MeshId == "rbxassetid://15346053833" then 
								WeaponName = "Military M4A1"
								break;
							end; 

							if Receiver.MeshId == "rbxassetid://15346209825" and Receiver.TextureID == "rbxassetid://15377390582" then 
								WeaponName = "Bruno's M4A1"
								break;
							end;
						end;
					end;
				end; 

				return Weapon, WeaponName;
			end;

			function Entities.Functions:GetDistance()
				if self.Character and self:GetRoot() then 
					local Distance = (Camera.CFrame.p - self:GetRoot().CFrame.p).Magnitude;

					return math.floor(Distance);
				end;

				return 0;
			end;

			function Entities.Functions:GetBoxSize(Distance)
				local character = self.Character
				if not character then
					return nil
				end
				
				local root = self:GetRoot()
				if not root then
					return nil
				end


				if (Camera.CFrame.p - root.CFrame.p).Magnitude <= Distance then 
				
					local MaxBoxWidth = 10
					local MaxBoxHeight = 20
					local MaxBoxDepth = 10
					
					local BoundingBoxPosition, BoundingBoxSize = Visuals.GetBoundingBox(character, root.CFrame)
					local HalfSize = BoundingBoxSize / 2
					
					local ClampedHalfSizeX = math.min(HalfSize.X, MaxBoxWidth / 2)
					local ClampedHalfSizeY = math.min(HalfSize.Y, MaxBoxHeight / 2)
					local ClampedHalfSizeZ = math.min(HalfSize.Z, MaxBoxDepth / 2)
					
					local ClampedBoundingBoxSize = Vector3.new(ClampedHalfSizeX * 2, ClampedHalfSizeY * 2, ClampedHalfSizeZ * 2)
					local ClampedBoundingBoxPosition = BoundingBoxPosition

					local corners = {
						ClampedBoundingBoxPosition * CFrame.new(ClampedHalfSizeX, ClampedHalfSizeY, ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(ClampedHalfSizeX, ClampedHalfSizeY, -ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(ClampedHalfSizeX, -ClampedHalfSizeY, ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(ClampedHalfSizeX, -ClampedHalfSizeY, -ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(-ClampedHalfSizeX, ClampedHalfSizeY, ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(-ClampedHalfSizeX, ClampedHalfSizeY, -ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(-ClampedHalfSizeX, -ClampedHalfSizeY, ClampedHalfSizeZ),
						ClampedBoundingBoxPosition * CFrame.new(-ClampedHalfSizeX, -ClampedHalfSizeY, -ClampedHalfSizeZ)
					}
					
					local minX, minY = math.huge, math.huge
					local maxX, maxY = -math.huge, -math.huge
					local onScreenCount = 0
					
					for _, corner in ipairs(corners) do
						local screenPos, onScreen = WTVP(Camera, corner.Position)
						if onScreen then
							onScreenCount = onScreenCount + 1
							minX = math.min(minX, screenPos.X)
							minY = math.min(minY, screenPos.Y)
							maxX = math.max(maxX, screenPos.X)
							maxY = math.max(maxY, screenPos.Y)
						end
					end
					
					if onScreenCount == 0 and character:FindFirstChild("Head") then
						local IsVisible = Visuals.IsPartVisible(character:FindFirstChild("Head"))
						return {
							Root = root,
							OnScreen = false,
							Visible = IsVisible,
							VisiblePart = IsVisible and character:FindFirstChild("Head") or nil;
						}
					end

					local Parts = {
						character:FindFirstChild(Library.Flags.AimbotPart.Value),
						character:FindFirstChild("Head"),
						character:FindFirstChild("HumanoidRootPart"),
						character:FindFirstChild("RightLowerLeg"),
						character:FindFirstChild("LeftLowerLeg"),
						character:FindFirstChild("RightUpperArm"),
						character:FindFirstChild("LeftUpperArm"),
					};
				
					local PassedVisibility = false
					local VisiblePart = nil
					for _, part in ipairs(Parts) do
						if part:IsA("BasePart") and Visuals.IsPartVisible(part) then
							PassedVisibility = true
							VisiblePart = part;
							break
						end
					end
					
					local BoxData = {}
					BoxData.Visible = PassedVisibility
					BoxData.VisiblePart = VisiblePart
					local Width = maxX - minX
					local Height = maxY - minY
					local MinWidth = 0
					local Size = Visuals.FloorVector(Vector2.new(math.max(Width, MinWidth), Height))
					local Position = Visuals.FloorVector(Vector2.new(minX, minY))
					local Center = Vector2.new(Position.X + Size.X / 2, Position.Y + Size.Y / 2)
					
					BoxData.Root = root;

					BoxData.RootPosition = root.CFrame.p
					BoxData.Height = Height
					BoxData.Width = Width
					BoxData.Size = Size
					BoxData.Position = Position
					BoxData.Center2D = Center
					BoxData.OnScreen = onScreenCount > 3
				
					return BoxData
				end;
			end;

			function Entities.Functions:GetInventory()
				local Text = ""
				local Weapon, Name = self:GetWeapon()
				local Attachments = Weapon and Weapon:FindFirstChild("Attachments") 
				if Attachments and #Attachments:GetChildren() > 0 then 
					local Items = {}
				
					for _, Value in ipairs(Attachments:GetChildren()) do 
						table.insert(Items, Value.Name);
					end
			
					if #Items > 0 then 
						Text = "[" .. table.concat(Items, ", ") .. "]"
					end
				end; 
				
				return Text                        
			end;

			function Entities.Functions:GetAmmo(Weapon, WeaponName)
				local Ammo, MaxAmmo, Passed = 0, 2, false

				return Ammo, MaxAmmo, Passed
			end;
			
			function Entities.Functions:IsDead()
				local IsDead = false
				if self.CurrentHealth <= 0 or (self.Character and self.Character.Humanoid:GetState() == Enum.HumanoidStateType.Dead) then
					IsDead = true
				end
				
				return IsDead
			end;
		end;
	end)();

