				end;

				local Weapon, WeaponName = nil, "None";
				for Index, Value in ipairs(Aimbot.TargetPart.Parent:GetChildren()) do 
					if Value:IsA("Model") and Weapons[Value.Name] then
						Weapon = Value;
						WeaponName = Value.Name;
						break;
					end;
				end;

				local WeaponTable = {};
				if Weapon and WeaponName then 
					if table.find(ItemNames, WeaponName) then 
						local Attachments = Weapon:FindFirstChild("Attachments"); 
						WeaponTable[#WeaponTable+1] = WeaponName
						if Attachments then 
