					Character:Toggle({Name = "Bunnyhop", Flag = "Bunnyhopflag", Description = "Bounce bounce"})
					local UIS = game:GetService("UserInputService")
						local function UpdateCharacter(char)
						Humanoid = char:WaitForChild("Humanoid")
					end
					if LocalPlayer.Character then
						UpdateCharacter(LocalPlayer.Character)
					end
					LocalPlayer.CharacterAdded:Connect(UpdateCharacter)
					RunService.RenderStepped:Connect(function()
						if Humanoid and Library.Flags.Bunnyhopflag.Value then
							if UIS:IsKeyDown(Enum.KeyCode.Space) then
								if tostring(Humanoid.FloorMaterial) ~= "Air" then
									Humanoid.Jump = true
								end
							end
						end
					end)

					Character:Toggle({
						Name = "Always Grounded",
						Flag = "AlwaysGrounded",
						Description = "Allows you to shoot while flying",
					});

						local function HookAlwaysGrounded(char)
						local hum = char and char:FindFirstChildOfClass("Humanoid")
						if not hum then return end

						for _, c in ipairs(getconnections(hum.StateChanged)) do
							local fn = c.Function
							if typeof(fn) == "function" then
								local i = debug.getinfo(fn)
								if i and i.short_src and i.short_src:find("ViewmodelController") then
									local Old
									Old = hookfunction(fn, LPH_NO_UPVALUES(function(oldState, newState, ...)
										if Library.Flags.AlwaysGrounded.Value then
											oldState = Enum.HumanoidStateType.Running
											newState = Enum.HumanoidStateType.Running
										end
										return Old(oldState, newState, ...)
									end))
								end
							end
						end
					end

					if LocalPlayer.Character then
						HookAlwaysGrounded(LocalPlayer.Character)
					end

					LocalPlayer.CharacterAdded:Connect(function(char)
						task.wait(1)
						HookAlwaysGrounded(char)
					end)
					Character:Toggle({
						Name = "Silent Step",
						Flag = "SilentStep",
						Description = "Removes footstep sounds",
					});
					local ToggleFootstep = SoundModule.ToggleFootstep
					SoundModule.ToggleFootstep = LPH_NO_VIRTUALIZE(function(...)
						local Arguments = {...}

						if Library.Flags.SilentStep.Value and Arguments[3] then
							return SoundModule:StopSound(Arguments[3])
						end

						return ToggleFootstep(...)
					end)

					local PlaySound = SoundModule.PlaySound
					SoundModule.PlaySound = LPH_NO_VIRTUALIZE(function(...)
						local Arguments = {...}

						if Library.Flags.SilentStep.Value and Arguments[2] and Arguments[2].Name == "WalkWater" then
							return SoundModule:StopSound(Arguments[2])
						end

