							loadedAuras.Blossom = value;
						else
							loadedAuras.Explosion = value;
						end;
					end;

					local function clearAura()
						if currentAura then
							currentAura:Destroy()
							currentAura = nil
						end
					end

					local function attachAura()
						local player = Players.LocalPlayer
						local char = player.Character
						if not char or not char:FindFirstChild("HumanoidRootPart") then return end

						local root = char.HumanoidRootPart
						clearAura()

						local auraName = Library.Flags.AuraType.Value
						local basePart = loadedAuras[auraName]
						if not basePart then return print('not found') end

						local auraClone = basePart:Clone()
						auraClone.Name = "ActiveAura"
						auraClone.Anchored = false
						auraClone.CanCollide = false
						auraClone.Parent = root

						auraClone.CFrame = root.CFrame * CFrame.Angles(0, math.rad(180), 0);

						currentAura = auraClone
					end

					RunService.Heartbeat:Connect(function()
						if not Library.Flags.EnableAura.Value then
							clearAura()
							return
						end

						local selected = Library.Flags.AuraType.Value

						if currentAura then
													local player = Players.LocalPlayer
						local char = player.Character
						if not char or not char:FindFirstChild("HumanoidRootPart") then return end

							for index, value in currentAura:GetDescendants() do
								if value:IsA('ParticleEmitter') then
									value.Color = ColorSequence.new(Library.Flags.AuraColor.Color)
								end;
							end;

							currentAura.CFrame = char.HumanoidRootPart.CFrame * CFrame.Angles(0, math.rad(180), 0);
						end;

						if not currentAura then
							attachAura()
							if currentAura then currentAura.Name = selected end
						end
					end)

