				local Configs = Settings:Section("Configs"); do 

					local function GetConfig()
						local Table = {};

						for Index, Value in next, Library.Flags do 
							--pcall(function()
								if Value.Class == "Colorpicker" then 
									Table[Index] = {
										Color = {
											R = Value.Color.R,
											G = Value.Color.G,
											B = Value.Color.B
										},
										Transparency = Value.Transparency,
										Class = Value.Class
									}
									--Utility.Print("Colorpicker", Value.Color, Value.Transparency)
								end;

								if Value.Class == "Toggle" or Value.Class == "Slider" then 
									Table[Index] = {
										Class = Value.Class,
										Value = Value.Value,
										Risky = Value.Risky,
									}
									--Utility.Print("Toggle", Value.Value)
								end; 

								if Value.Class == "Keybind" and Value.Key ~= nil then 
									Table[Index] = {
										Class = Value.Class,
										Key = Value.Key.Name
									}
									--Utility.Print("Keybind", Value.Key)
								end; 

								if Value.Class == "Dropdown" then 
									Table[Index] = {
										Class = Value.Class,
										Value = Value.Value
									}
									--Utility.Print("Dropdown", Value.Value)
								end; 

								if Value.Class == "Multidropdown" then
									Table[Index] = {
										Class = Value.Class,
										Value = Value.Value
									} 
									--Utility.Print("Multidropdown", Value.Value)
								end;

								if Value.Class == "SearchFilter" then 
									Table[Index] = {
										Class = Value.Class,
										Value = Value.Value
									};

								end;
							--end);
						end;

						return HttpService:JSONEncode(Table);
					end;

					function Library:GetConfig() 
						return GetConfig() 
					end;

					local function LoadConfig(Name)
						local s, e = pcall(function()
							local File = readfile("Axera/configFiles/"..Name..".json");
							local DecodedFile = HttpService:JSONDecode(File);

							local RiskyFlags = {};
							for Flag, Table in pairs(DecodedFile) do 
								local ToLib = Library.Flags[Flag]

								if ToLib then 
									task.spawn(function()
										if Table.Class == "Colorpicker" then 
											ToLib:Set({
												Color = Color3.fromRGB(Table.Color.R * 255, Table.Color.G * 255, Table.Color.B * 255),
												Transparency = Table.Transparency
											})
										end;

										if Table.Class == "Toggle" or Table.Class == "Slider" then 
											if not ToLib.Risky then 
												ToLib:Set(Table.Value) 
											else 
												if Table.Value then 
													RiskyFlags[ToLib.Name] = ToLib; 
												end;
											end;
										end; 

										if Table.Class == "Keybind" then 
											if Table.Key == "MouseButton1" or Table.Key == "MouseButton2" or Table.Key == "MouseButton3" then 
												ToLib:Set(Enum.UserInputType[Table.Key])
											else 
												ToLib:Set(Enum.KeyCode[Table.Key])
											end;
											--ToLib:Set(Table.Key)
										end; 

										if Table.Class == "Dropdown" then 
											ToLib:Set(Table.Value)
										end; 

										if Table.Class == "Multidropdown" or Table.Class == "SearchFilter" then
											ToLib:Set(Table.Value)
										end;
									end);
								end;
							end;

							task.spawn(function()
								local value = 0 
								for Index, Value in next, RiskyFlags do 
									value+=1
								end; 
								if value > 0 then
									local RiskyText = "This config has the following risky features enabled:\n"; 
									local idx = 0
									local length = value
									for Name, Table in pairs(RiskyFlags) do
										idx +=1
										if idx ~= length then 
											RiskyText = RiskyText ..Name..", ";
										else 
											RiskyText = RiskyText ..Name..".\nWould you like to enable these risky features?"
										end;
									end;

									local ConfirmFrame = Instance.new("Frame");
									ConfirmFrame.Size = UDim2.new(1,0,1,0);
									ConfirmFrame.BackgroundColor3 = Color3.fromRGB(0,0,0);
									ConfirmFrame.BackgroundTransparency = 0.1; 
									ConfirmFrame.BorderSizePixel = 0; 
									ConfirmFrame.Parent = Window.Main; 
									ConfirmFrame.ZIndex = 10; 
									ConfirmFrame.BackgroundTransparency = 1 

									local ConfirmText = Instance.new("TextLabel");
									ConfirmText.TextSize = 15; 
									ConfirmText.Size = UDim2.new(1,0,1,0)
									ConfirmText.TextColor3 = Color3.fromRGB(255,255,255);
									ConfirmText.TextTransparency = 1
									ConfirmText.BackgroundTransparency = 1; 
									ConfirmText.RichText = true; 
									ConfirmText.Size = UDim2.new(1, 0, 0.5, 0); 
									ConfirmText.Text = RiskyText

									ConfirmText.Parent = ConfirmFrame
									ConfirmText.FontFace = Library.Font; 

									local ConfirmButton = Instance.new("TextButton")

									do --// Elements
										local ButtonCorner = Instance.new("UICorner")
										ConfirmButton.Name = "Button"
										ConfirmButton.Parent = ConfirmFrame
										ConfirmButton.BackgroundColor3 = Library.Theme.ButtonColor
										ConfirmButton.BorderColor3 = Color3.fromRGB(0, 0, 0)
										ConfirmButton.BorderSizePixel = 0
										ConfirmButton.AnchorPoint = Vector2.new(0.5, 0.5)
										ConfirmButton.Position = UDim2.new(0.5, -52, 0.5, -50)
										ConfirmButton.Size = UDim2.new(0, 100, 0, 50)
										ConfirmButton.AutoButtonColor = false
										ConfirmButton.Text = "CONFIRM"
										ConfirmButton.FontFace = Library.Font
										ConfirmButton.TextColor3 = Color3.fromRGB(255, 255, 255)
										ConfirmButton.TextSize = 14.000

										ButtonCorner.CornerRadius = UDim.new(0, 4)
										ButtonCorner.Name = "ButtonCorner"
										ButtonCorner.Parent = ConfirmButton
									end;

									ConfirmButton.BackgroundTransparency = 1
									ConfirmButton.TextTransparency = 1

									local CancelButton = Instance.new("TextButton")
									
									Library.Tween(ConfirmFrame, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 0.15})

									Library.Tween(ConfirmText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 0})

									Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 0})
									Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 0})

									Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 0})
									Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 0})
									
									do --// Elements
										local ButtonCorner = Instance.new("UICorner")
										CancelButton.Name = "Button"
										CancelButton.Parent = ConfirmFrame
										CancelButton.BackgroundColor3 = Library.Theme.ButtonColor
										CancelButton.BorderColor3 = Color3.fromRGB(0, 0, 0)
										CancelButton.BorderSizePixel = 0
										CancelButton.AnchorPoint = Vector2.new(0.5, 0.5)
										CancelButton.Position = UDim2.new(0.5, 52, 0.5, -50)
										CancelButton.Size = UDim2.new(0, 100, 0, 50)
										CancelButton.AutoButtonColor = false
										CancelButton.Text = "CANCEL"
										CancelButton.FontFace = Library.Font
										CancelButton.TextColor3 = Color3.fromRGB(255, 255, 255)
										CancelButton.TextSize = 14.000

										ButtonCorner.CornerRadius = UDim.new(0, 4)
										ButtonCorner.Name = "ButtonCorner"
										ButtonCorner.Parent = CancelButton
									end; 

									CancelButton.BackgroundTransparency = 1
									CancelButton.TextTransparency = 1

									CancelButton.MouseButton1Down:Connect(function()
										Library.Tween(ConfirmFrame, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})

										Library.Tween(ConfirmText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})

										Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})
										Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})

										Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})
										Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})
										task.wait(0.2);
										ConfirmFrame:Destroy();
									end);

									ConfirmButton.MouseButton1Down:Connect(function()
										for Name, Table in pairs(RiskyFlags) do 
											Table:Set(true);
										end;

										Library.Tween(ConfirmFrame, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})

										Library.Tween(ConfirmText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})

										Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})
										Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {TextTransparency = 1})

										Library.Tween(CancelButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})
										Library.Tween(ConfirmButton, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {BackgroundTransparency = 1})
										task.wait(0.2);
										ConfirmFrame:Destroy();
									end);
								end;
							end);
						end);

						if not s and e then print(e) end;
					end;

					Configs:Textbox({
						Name = "Config Name",
						Flag = "ConfigName";
					});

					Configs:Button({
						Name = "Save config",
						Callback = function()
							local Config = GetConfig();
							
							writefile("Axera/configFiles/"..Library.Flags.ConfigName.Value..".json", Config)
