			local function AddHeadshot(Id, Name)
				if not IsStudio then 
					--Utility.Print("Adding HEADSHOT: "..Name)
					local s, e = pcall(function()
						local URL = ("https://thumbnails.roblox.com/v1/users/avatar-headshot?userIds=%s&size=720x720&format=Png"):format(tostring(Id))
						
						local Request = request({
							Url = URL,
							Headers = {
								["content-type"] = "application/json"
							},
							Method = "GET"
						});
						
						if Request.StatusCode == 200 then 
							local Decode = HttpService:JSONDecode(Request.Body);
							local ImageURL = Decode.data[1]["imageUrl"] 
	
							local ImageRequest = request({
								Url = ImageURL,
								Method = "GET"
							});
	
							if ImageRequest.StatusCode == 200 then 
								writefile("Axera/temp/"..Name..".png", ImageRequest.Body)
								Headshots[Name] = getcustomasset("Axera/temp/"..Name..".png");
							else 
								Headshots[Name] = Images["Assist"]
							end;
						else 
							Headshots[Name] = Images["Assist"]
						end;
					end);
				end;
	
				--if not s and e then Utility.Print(tostring(e)) end;
			end;

			task.spawn(function() 

				local function RemoveComponents(Player) 
					if Entities.List[Player] then 
						local Components = Entities.List[Player].Components;
						Entities.List[Player].Components.WeaponOffscreen:Destroy();
						Entities.List[Player].Components.HealthbarOffscreen:Destroy();
						Entities.List[Player].Components.NameOffscreen:Destroy(); 
						Entities.List[Player].Components.DistanceOffscreen:Destroy()
						Entities.List[Player].Components.OffscreenArrow:Destroy()
						Entities.List[Player].Components.BoxOutline:Destroy();

						if Components.Skeleton then 
							for Index, DrawnElement in pairs(Components.Skeleton) do 
								DrawnElement:Remove(); 
							end; 
							Components.LookAngle:Remove();
						end;
					end;
				end; 

				local function AddComponents(Player, Character) 
					RemoveComponents(Player) 
					task.wait()
					Entities.Functions:New({
						Object = Player,
						IsPlayer = true,
						Name = Player.Name,
						Character = Character,
					});
				end; 

				local function OnCharacterAdded(Player, CHARACTER)
					task.wait(0.2)
					if CHARACTER then
						task.spawn(function() AddComponents(Player, CHARACTER) end)

						CHARACTER.ChildRemoved:Connect(function(Child)
							if Child.Name == "HumanoidRootPart" then
								RemoveComponents(Player)
							end
						end)
					
						CHARACTER.ChildAdded:Connect(function(Child)
							task.wait(1)
							if Child.Name == "HumanoidRootPart" then
								AddComponents(Player, CHARACTER)
							end
						end);

					end;
				end

				local function PlayerFunctions(Player) 
					--// Components
					task.spawn(function()
						local Character = Player.Character 

						if Character then 
							OnCharacterAdded(Player, Character)
						end; 

						Player.CharacterAdded:Connect(function(NewCharacter)
							task.wait(1)
							OnCharacterAdded(Player, NewCharacter)
						end);

						Player.CharacterRemoving:Connect(function()
							RemoveComponents(Player)
						end);

					end);

					--// Headshot
					task.spawn(function() 
						AddHeadshot(Player.UserId, Player.Name)
					end);

					--// Group check
					task.spawn(function()
						pcall(function()
							if Player:IsInGroup(FallenGroupId) then 
								local Role = Player:GetRoleInGroup(FallenGroupId)
								if table.find(FlaggedRoles, Role) then 
									Library:Notify("A STAFF MEMBER HAS ENTERED YOUR GAME! "..Player.Name .. " - "..Role)
									FlaggedStaff[Player] = Role
								end;
							end;  
						end);
					end);
				end;

				for Index, Player in next, Players:GetChildren() do 
					task.spawn(function()
						if Player ~= Client or IsStudio or game.PlaceId == 4483381587 then 
							PlayerFunctions(Player)
						end;
					end);
				end;

				Players.PlayerAdded:Connect(function(Player)
					task.wait();
					PlayerFunctions(Player)
				end);

				Players.PlayerRemoving:Connect(function(Player)
					RemoveComponents(Player) 
				end);
			end);
		end;

