													return table.find(Library.Flags.AllowedItems.Value, Name);
												end;

												return true;
											end; 

											GetCustomName = function(Entity)
												if Entity.Object:FindFirstChild("Item") then 
													local Name = Entity.Object.Name
													pcall(function()
														local Decode = HttpService:JSONDecode(Entity.Object.Item.Value)
														local Amount = Decode and Decode.Amount
						
														if Amount and Amount > 1 then 
															Name = Entity.Object.Name .. "   [x"..tostring(Amount).."]"
														end
													end)
													return Name
												end
												return Entity.Object.Name
											end,
											GetRoot = function(Entity)
												return Entity.Object.PrimaryPart
											end,
										})
									end
						
