											Items.List[Value].Components.Name:Destroy()
											Items.List[Value] = nil
										end
									end
						
									local MainPart = Value:FindFirstChild("Main") or Value:FindFirstChildOfClass("MeshPart")
									if MainPart then
										AddDroppedItem()
									end
						
									Value.ChildAdded:Connect(function(child)
										task.wait(0.3);
										if (child.Name == "Main" or child:IsA("MeshPart")) and not Items.List[Value] then
											AddDroppedItem()
										end
									end)
						
									Value.ChildRemoved:Connect(function(child)
