							local function HandleBase(BaseFolder)
								if BaseFolder.Name ~= "Base" then return end

								local AutoTurretFolder = BaseFolder:FindFirstChild("Auto Turret")
								if not AutoTurretFolder then return end

								for _, Value in next, AutoTurretFolder:GetChildren() do
									AddAutoTurret(Value)
								end

								AutoTurretFolder.ChildAdded:Connect(function(Value)
									task.wait(0.3)
									AddAutoTurret(Value)
								end)

