									if Items.List[Value] then 
										Items.List[Value].Components.Name:Destroy()
										Items.List[Value] = nil
									end
								end)
							end

							for _, BaseFolder in next, Bases:GetChildren() do
								HandleBase(BaseFolder)
							end

							Bases.ChildAdded:Connect(function(BaseFolder)
								task.wait(0.3)
								HandleBase(BaseFolder)
							end)

						end
