								local MainPart = Value:FindFirstChild("Main")
								if MainPart then
									AddLargeGiftItem()
								end
						
								Value.ChildAdded:Connect(function(child)
									task.wait(0.3);
									if child.Name == "Main" and not Items.List[Value] then
										AddLargeGiftItem()
									end
								end)
						
								Value.ChildRemoved:Connect(function(child)
									if child.Name == "Main" then
										RemoveGiftItem()
									end
								end)
							--end)
						end
						
					
						for Index, Value in next, LargeGift:GetChildren() do 
							AddLargeGift(Value)
						end
					
						LargeGift.ChildAdded:Connect(function(Value)
							task.wait(0.3)
							AddLargeGift(Value)
						end)
					
						LargeGift.ChildRemoved:Connect(function(Value)
							--pcall(function()
								if Items.List[Value] then 
									Items.List[Value].Components.Name:Destroy()
									Items.List[Value] = nil
								end
							--end)
						end)
					end;

				end;
			end);

			if not s and e then 
				rconsoleprint(tostring(e))
			end;
		end;

		
		do --// camera 
			Camera:GetPropertyChangedSignal("FieldOfView"):Connect(function()
				if Library.Flags.ZoomToggle then 
					if Library.Flags.ZoomToggle.Value and Library.Flags.ZoomKey.Value then 
						Camera.FieldOfView = Library.Flags.ZoomFOV.Value;
						return;
					end;

					if Library.Flags.ModFOV.Value then 
						Camera.FieldOfView = Library.Flags.ModFieldOfView.Value;
						return;
					end;
				end;
			end);
		end;

		do --// bindable events 

			local function CreateHitEffect(HitPosition)
				local Model = Instance.new("Model", Workspace)
				local Part0 = Instance.new("Part")
				Part0.Size = Vector3.new(0.2, 0.2, 0.2)
				Part0.Position = HitPosition
				Part0.Anchored = true
				Part0.CanCollide = false
				Part0.Transparency = 1  
				Part0.Parent = Model
				Part0.CanQuery = false
			
				local Emitter = Instance.new("ParticleEmitter")
				Emitter.Parent = Part0
			
				Emitter.Texture = "rbxassetid://10198439352" 
				Emitter.Lifetime = NumberRange.new(0.3, 0.5) 
				Emitter.Rate = 0  
				Emitter.Speed = NumberRange.new(0, 0)
				Emitter.RotSpeed = NumberRange.new(0, 0)
				Emitter.Brightness = 20
				Emitter.Size = NumberSequence.new({
					NumberSequenceKeypoint.new(0, 8),
					NumberSequenceKeypoint.new(1, 8),
				})
				Emitter.Color = ColorSequence.new(Color3.new(1, 1, 1), Library.Flags.HitColor.Color) 
				Emitter.LightEmission = 540
				Emitter.VelocitySpread = 0
				Emitter.Enabled = true
				Emitter.EmissionDirection = "Top"
				Emitter.FlipbookLayout = "Grid4x4"
				Emitter.FlipbookMode = "OneShot"
				Emitter.Shape = "Box"
				Emitter.ShapeInOut = "Outward"
				Emitter.ShapeStyle = "Volume"
				
				Emitter:Emit(1)
			
				Emitter.Transparency = NumberSequence.new({
					NumberSequenceKeypoint.new(0, 0),  
					NumberSequenceKeypoint.new(1, 0.7), 
				})
			
				Delay(2, function()
					Part0:Destroy()
					Model:Destroy()
				end)
			end

			--// VFX Ordered
			task.spawn(function()
				if true then 
					local ClientSignals = ReplicatedStorage:WaitForChild("ClientSignals", 5)
					local VFXOrdered = ClientSignals.VFXOrdered; 

					local Params = RaycastParams.new(); 

					Params.FilterDescendantsInstances = { 
						Workspace:FindFirstChild("VFX"),
					};

					VFXOrdered.OnClientEvent:Connect(function(...)
						local Args = {...};
						local Order = Args[1]; 
					
						if Order == "CreateProjectile" and Library.Flags.Tracers.Value then 
							local RemoteInformation = Args[2][1]; 
							if RemoteInformation then 
								local RayInfo = Workspace:Raycast(RemoteInformation.Position, RemoteInformation.Direction * RemoteInformation.MaxRange, Params);
					
								if RayInfo and RayInfo.Position then 
									FireEvent:Fire("BulletTracer", RemoteInformation.Position, RayInfo.Position, "Enemy")
								end;
							end; 
						end;
					end);
				end;
			end);

			--// Fire Event handler (Tracers, HitEffects)
			FireEvent.Event:Connect(function(Name, Origin, Destination, Type)
				if Name == "Notification" then 
					local Part = Origin; 
					local Weapon = Destination; 
			
					if Weapon then 
						local Distance = (Part.CFrame.p - Camera.CFrame.p).Magnitude
						Library:Notify("Hit "..Part.Parent.Name .. " in the "..Part.Name .. " from "..tostring(math.floor(Distance)) .. " studs away using "..Weapon.Name);
					else 
						local Distance = (Part.CFrame.p - Camera.CFrame.p).Magnitude
						Library:Notify("Hit "..Part.Parent.Name .. " in the "..Part.Name .. " from "..tostring(math.floor(Distance)).. " studs away");
					end;

					if Part.Name == "Head" then 
						local sound = HeadSound:Clone()
						sound.Parent = CoreGui
						sound:Play()
						delay(1, function() sound:Destroy() end)
					else 
						local sound = HitSound:Clone()
						sound.Parent = CoreGui
						sound:Play()
						delay(1, function() sound:Destroy() end)
					end
				end
				
				if Name == "HitEffect" then 
					CreateHitEffect(Origin)
				end; 

				if Name == "BulletTracer" then 
					local Color = Library.Flags[Type.."TracerColor"].Color; 
					local Model = Instance.new("Model", Workspace); 
					Model.Name = "Model";

					local Part0 = Instance.new("Part"); do 
						Part0.CanQuery = false
						Part0.Position = Origin;
						Part0.Name = "Part";
						Part0.Anchored = true;
						Part0.Transparency = 1;
						Part0.CanCollide = false;
						Part0.Parent = Model;
						Part0.Size = Vector3.new(0.0001, 0.0001, 0.0001); 
					end;

					local Part1 = Instance.new("Part"); do 
						Part1.CanQuery = false
						Part1.Position = Destination;
						Part1.Anchored = true;
						Part1.Name = "Part"
						Part1.Transparency = 1;
						Part1.CanCollide = false;
						Part1.Parent = Model;
						Part1.Size = Vector3.new(0.0001, 0.0001, 0.0001); 
					end;

					local Attachment0 = Instance.new("Attachment", Part0)
					local Attachment1 = Instance.new("Attachment", Part1)

					local Beam = Instance.new("Beam"); do 
						Beam.FaceCamera = true;
						Beam.Name = "Beam"
						Beam.Color = ColorSequence.new({
							ColorSequenceKeypoint.new(0, Color),
							ColorSequenceKeypoint.new(1, Color),
						});
						Beam.LightEmission = 0;
						Beam.LightInfluence = 0;
						Beam.Width0 = 0.4;
						Beam.Width1 = 0.4;
						Beam.Texture = "rbxassetid://128372145766358";
						Beam.TextureLength = 30;
						Beam.TextureMode = Enum.TextureMode.Wrap;
						Beam.TextureSpeed = 2;
						Beam.Parent = Model;
						Beam.Brightness = 150;
						Beam.Attachment0 = Attachment0;
						Beam.Attachment1 = Attachment1;
					end;

					Delay(Library.Flags.TracerTime.Value, function()
						local Tween = TweenService:Create(Beam, TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), { 
							Width0 = 0,
							Width1 = 0,
							TextureSpeed = 0,
							Brightness = 75
						})

						Tween:Play()
						Tween.Completed:Wait()
						Model:Destroy()
					end);
				end;
			end);
		end;

		do -- // viewmodels 
			local VFX = Workspace:WaitForChild("VFX", 2);
			local VMs = VFX and VFX:WaitForChild("VMs", 1);
			local enabled = false;

			if VMs and enabled then 
				VMs.ChildAdded:Connect(function(Child) 
						--CoreGui:FindFirstChild("yeah this worked"):Destroy()
						task.wait(0.1)
						if Child:IsA("Model") and Weapons[Child.Name] and Library.Flags.ViewmodelChams and Library.Flags.ViewmodelChams.Value then
							Utility.UpdateViewmodel(Child)
						end;
				end);
			end;
		end;
	end)();
end;



do --// loops 
	local Atmosphere = Lighting:FindFirstChild("Atmosphere"); 
	local OldDensity = Atmosphere and Atmosphere.Density

	do --// Main
		local Current = CFrame.new();
	
		local Modules = ReplicatedStorage:FindFirstChild("Modules");
		local ToolInfo = Modules and Modules:FindFirstChild("ToolInfo")  and require(Modules:FindFirstChild("ToolInfo"))

		RunService.RenderStepped:Connect(LPH_NO_VIRTUALIZE(function(DeltaTime)
			do --// Main Entities (Targetting and ESP)
				--// Targetting variables 
				local LastDistance, ClosestTarget, ActualPlayer = math.huge, nil, nil;
				local Target2d = nil;
				--// ESP Variables.. better to set them up here then inside the loop
				local FlagManipulation = Library.Flags.SilentManipulation.Value and Library.Flags.ManipulationKey.Value

				for Object, Entity in next, Entities.List do
					Entity.Character = Entity:GetCharacter()
					local Class = Entity.IsPlayer and "Player" or "AI"
					local ESPBoxFlag = Library.Flags[Class.."_ESPBox"] and Library.Flags[Class.."_ESPBox"].Value
					local ESPNameFlag = Library.Flags[Class.."_ESPName"] and Library.Flags[Class.."_ESPName"] .Value
					local ESPDistanceFlag = Library.Flags[Class.."_ESPDistance"] and Library.Flags[Class.."_ESPDistance"].Value
					local ESPVIPFlag = Library.Flags[Class.."_ESPVIP"] and Library.Flags[Class.."_ESPVIP"].Value
					local ESPWeaponFlag = Library.Flags[Class.."_ESPWeapon"] and Library.Flags[Class.."_ESPWeapon"].Value
					local ESPFlagsFlag = Library.Flags[Class.."_ESPFlags"] and Library.Flags[Class.."_ESPFlags"] .Value
					local ESPHealthbarFlag = Library.Flags[Class.."_ESPHealthbar"] and Library.Flags[Class.."_ESPHealthbar"].Value
					local ESPSkeletonFlag = Library.Flags[Class.."_ESPSkeleton"] and Library.Flags[Class.."_ESPSkeleton"].Value 
					local ESPLookAngleFlag = Library.Flags[Class.."_ESPLookAngle"] and Library.Flags[Class.."_ESPLookAngle"] .Value 
					local HighlightFlag = Library.Flags.PlayerHighlights and Library.Flags.PlayerHighlights.Value; 
					local PulseHighlights = Library.Flags.PulseHighlights and Library.Flags.PulseHighlights.Value; 
	
					local ESPFlagList = Library.Flags[Class.."_ESPFlagList"] and Library.Flags[Class.."_ESPFlagList"].Value or {};
					local FlagAimed = table.find(ESPFlagList, "Aiming")
					local FlagReloading = table.find(ESPFlagList, "Reloading")
					local FlagClans = table.find(ESPFlagList, "Clan");
					local FlagHealing = table.find(ESPFlagList, "Healing")
					local FlagStaff = table.find(ESPFlagList, "Staff"); 
	
					local OffFlags = Library.Flags[Class.."_OffscreenFlags"] and Library.Flags[Class.."_OffscreenFlags"].Value or {};
	
					local OffNameFlag = table.find(OffFlags, "Name");
					local OffDistanceFlag = table.find(OffFlags, "Distance");
					local OffWeaponFlag = table.find(OffFlags, "Weapon");
					local OffHealthFlag = table.find(OffFlags, "Health");

					local BoxData = Entity:GetBoxSize(Library.Flags[Class.."_ESPMaxDistance"].Value)
					local Components = Entity.Components
					local Skeleton = Components.Skeleton
					local Box = Components.Box
					local BoxOutline = Components.BoxOutline
					local BoxStroke = Components.BoxStroke
					local BoxOutlineStroke = Components.BoxOutlineStroke
					local NameText = Components.Name
					local DistanceText = Components.Distance
					local WeaponText = Components.Weapon
					local FlagsText = Components.Flags
					local VIPText = Components.VIP
					local Healthbar = Components.Healthbar
					local HealthbarInvert = Components.HealthbarInvert 
					
					local Highlight = Components.Highlight; 
					local ESPEnabled = Library.Flags[Class.."_ESPEnabled"] and Library.Flags[Class.."_ESPEnabled"].Value
					if BoxData and BoxData.OnScreen and (ESPEnabled or Library.Flags.AimbotEnabled.Value) and not Entity.Character:GetAttribute("Destroyed") then
						Components.OffscreenArrow.Visible = false
						Components.NameOffscreen.Visible = false 
						Components.DistanceOffscreen.Visible = false
						Components.WeaponOffscreen.Visible = false 
						Components.HealthbarOffscreen.Visible = false

						local Root = BoxData.Root; 
						local VisiblePart = BoxData.VisiblePart
						local Position = BoxData.Position
						local Size = BoxData.Size
						local RootPosition = BoxData.RootPosition
						local Distance = (Camera.CFrame.p - RootPosition).Magnitude

						Entity.Visible = BoxData.Visible
						local Humanoid = Root and Entity.Character:FindFirstChildOfClass("Humanoid")
						do --// Targetting 
						
							if not Entity.Friendly and Library.Flags.AimbotEnabled.Value and (Library.Flags.AimbotKey.Value or Library.Flags.AlwaysTarget.Value) and Humanoid and Root and Humanoid.Health >= 0.05 then --// The Actual Math for Targetting
								task.spawn(function()
									local Distance = Utility.GetDistanceFromCenter(Entity.Character:FindFirstChild("HumanoidRootPart"))
									if Distance <= (Visuals.FOVCircle.AbsoluteSize.X / 2)then 
										if not ClosestTarget or Distance < LastDistance then

											if Library.Flags.VisibleCheck.Value then 
												ClosestTarget = VisiblePart
											else 
												ClosestTarget = Entity.Character:FindFirstChild(Library.Flags.AimbotPart.Value);
											end;

											if Library.Flags.RandomizeHitPart.Value then 
												local Parts = {}; 

												for Index, Value in pairs(Entity.Character:GetChildren()) do 
													if Value:IsA("BasePart") and Visuals.IsPartVisible(Value) then 
														table.insert(Parts, Value)
													end;
												end;

											if #Parts > 0 then
												local Part = Parts[math.random(1, #Parts)];
												if Part then
													ClosestTarget = Part;
												end;
											end;
										end;

											if Entity.Character.Name == "BTR" then 
												ClosestTarget = Entity.Character:FindFirstChild("HumanoidRootPart") 
											end; 

											ActualPlayer = Object
											ActualPlayerName = Object.Name
											LastDistance = Distance
										end;
									end;
								end)
							end;
						end;

						do --// ESP
							if ESPEnabled and Humanoid.Health >= 0.05 then  --// ESP
								local ElementColor = BoxData.Visible and Library.Flags.ESPVisibleColor.Color or Library.Flags.ESPOccludedColor.Color
								local SkeletonColor = Library.Flags.ESPVisibleColor.Color 
								local SkeletonOccludedColor = Library.Flags.ESPOccludedColor
								if not Entity.IsPlayer then 
									if Entity.Boss then 

										SkeletonColor = Library.Flags.BossVisibleColor.Color 
										SkeletonOccludedColor = Library.Flags.BossOccludedColor
										ElementColor = BoxData.Visible and Library.Flags.BossVisibleColor.Color or Library.Flags.BossOccludedColor.Color
									else 
										SkeletonColor = Library.Flags.AIVisibleColor.Color 
										SkeletonOccludedColor = Library.Flags.AIOccludedColor
										ElementColor = BoxData.Visible and Library.Flags.AIVisibleColor.Color or Library.Flags.AIOccludedColor.Color
									end;
								end; 

								if Object == Aimbot.Target then 
									ElementColor = Library.Flags.ESPTargetColor.Color
								end;

								BoxOutline.Position = UDim2.new(0, Position.X, 0, Position.Y)
								BoxOutline.Size = UDim2.new(0, Size.X, 0, Size.Y)

								BoxOutline.Visible = true

								BoxStroke.Enabled = ESPBoxFlag
								BoxOutlineStroke.Enabled = ESPBoxFlag

								Library.Tween(BoxStroke, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Color = ElementColor})
								--BoxStroke.Color = ElementColor

								local TopBounds = -18
								local BottomBounds = 0

								--// Name Text
								if ESPNameFlag then
									if not Entity.Boss then

										if Entity.IsPlayer and Library.Flags.ShowDisplayName.Value then 
											NameText.Text = Object.DisplayName 
										else 
											NameText.Text = Entity.Name
										end;
									else 
										NameText.Text = "[BOSS]  "..Entity.Name
									end;
									Library.Tween(NameText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextColor3 = ElementColor})
									--NameText.TextColor3 = ElementColor
									NameText.Visible = true
								else
									NameText.Visible = false
									TopBounds = TopBounds + 10
								end

								--// Distance Text
								if ESPDistanceFlag then
									DistanceText.Text = string.format("%ds", math.floor(Distance))
									Library.Tween(DistanceText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextColor3 = ElementColor})
									--DistanceText.TextColor3 = ElementColor
									DistanceText.Visible = true
									TopBounds = TopBounds - 11
								else
									TopBounds = TopBounds - 11
									DistanceText.Visible = false
								end

								--// VIP Text
								if ESPVIPFlag then
									VIPText.Visible = true
									if Object:GetAttribute("VIP") then
										VIPText.Text = "VIP";
										VIPText.TextColor3 = Color3.fromRGB(243, 182, 12);
									else
										VIPText.Text = "Standard";
										VIPText.TextColor3 = Color3.fromRGB(147, 163, 204) ;
									end

									if Database.Users[tostring(Entity.Object.UserId)] and CanViewOthers then
										local Role = Database.Users[tostring(Entity.Object.UserId)].Role
										if Object:GetAttribute("VIP") then 
											VIPText.Text = "VIP - AXERA - "..Role;
										else 
											VIPText.Text = "AXERA - "..Role;
										end;
										VIPText.TextColor3 = Library.Theme.Accent;
									end;

									VIPText.Position = UDim2.new(0, 0, 0, TopBounds)
									TopBounds = TopBounds - 11
								else
									VIPText.Visible = false
								end

								--// Weapon Text
								if ESPWeaponFlag then
									local Weapon, WeaponName = Entity:GetWeapon()
									WeaponText.Text = WeaponName
									Library.Tween(WeaponText, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextColor3 = ElementColor})
									--WeaponText.TextColor3 = ElementColor
									WeaponText.Visible = true
									BottomBounds = BottomBounds + 12
								else
									WeaponText.Visible = false
								end

								--// Flags Text
								if ESPFlagsFlag then
									FlagsText.Visible = true
									FlagsText.Position = UDim2.new(0, 0, 1, BottomBounds)
									FlagsText.Text = ""
									local Weapon, WeaponName = Entity:GetWeapon();
									local Humanoid = Entity.Character:FindFirstChildOfClass("Humanoid");
									local Root = Entity.Character:FindFirstChild("HumanoidRootPart")
									if not setreadonly or game.PlaceId == 8392422325 then
										if FlagAimed then FlagsText.Text = FlagsText.Text .. "Aiming\n" end
										if FlagReloads then FlagsText.Text = FlagsText.Text .. "Reloading\n" end
										if FlagHealing then FlagsText.Text = FlagsText.Text .. "Healing\n" end
										if FlagStaff then FlagsText.Text = FlagsText.Text .. "Staff\n" end

									else
										if Humanoid and Weapon then
											local Tracks = Humanoid:GetPlayingAnimationTracks();
											if FlagAimed then 
												if Weapon then 
													if WeaponName == "Wooden Bow" then 
													
														if Root and Root:FindFirstChild("Wooden BowDraw") and Root:FindFirstChild("Wooden BowDraw").IsPlaying then 
															FlagsText.Text = FlagsText.Text .."Aiming\n"
														end;
													end;
						
													for Index, Value in ipairs(Tracks) do 
														if Value.Animation.AnimationId == "rbxassetid://10982316984" then 
															FlagsText.Text = FlagsText.Text .."Aiming\n"
														end;
													end;
												end;
											end;

											if FlagHealing then 
												for Index, Value in ipairs(Tracks) do 
													if Value.Animation.AnimationId == "rbxassetid://14860445359" or Value.Animation.AnimationId == "rbxassetid://2529243689" then 
														FlagsText.Text = FlagsText.Text .."Healing\n"
													end;
												end;
											end;

											if FlagReloading then 
												local MagIn = Root:FindFirstChild(WeaponName.. "MagIn")
												local MagOut = Root:FindFirstChild(WeaponName .. "MagOut")
					
												if WeaponName == "Crossbow" then 
													MagIn = Root:FindFirstChild("CrossbowPlaceArrow");
													MagOut = Root:FindFirstChild("CrossbowPull")
												end;
					
												if MagIn and MagOut and (MagIn.IsPlaying or MagOut.IsPlaying) then 
													FlagsText.Text = FlagsText.Text .. "Reloading\n"
												end;
											end;

											if FlagClans then 
												if Object:GetAttribute("ClanTag") then 
													FlagsText.Text = FlagsText.Text .. "Clan: "..tostring(Object:GetAttribute("ClanTag")).."\n";
												end;
											end;
											
										end;

										if Utility.ManipulatedPosition and FlagManipulation and Object == Aimbot.Target and Aimbot.TargetPart then 

											FlagsText.Text = FlagsText.Text.."MANIPULATED"
										end;

										if FlaggedStaff[Object] then 
											FlagsText.Text = "STAFF: "..FlaggedStaff[Object];
										end;
									end
								else
									FlagsText.Visible = false
								end

								--// Healthbar
								if ESPHealthbarFlag then
									Healthbar.Visible = true
									local Health, MaxHealth = Entity:GetHealth()
									if not Entity.PreviousHealth then 
										Entity.PreviousHealth = 100;
									end;

									if tick() - Entity.LastUpdate > 0.3 then
										Entity.LastUpdate = tick();
										Entity.PreviousHealth = math.floor(Health)

										local LerpedColor = Library.Flags.HealthbarLower.Color:lerp(Library.Flags.HealthbarPositive.Color, Entity.PreviousHealth  / MaxHealth)
										Library.Tween(Healthbar, TweenInfo.new(0.3, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut), {BackgroundColor3 = LerpedColor})

										Healthbar.Size = UDim2.new(0, 1, 1, 4)

										Library.Tween(HealthbarInvert, TweenInfo.new(0.3, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut), {Size = UDim2.new(1, 0, 1 - (Entity.PreviousHealth / MaxHealth), 0)});
										Entity.Components.HealthText.Text = Entity.PreviousHealth

									end
								else
									Healthbar.Visible = false
								end

								--// LookAngle 
								if ESPLookAngleFlag and Entity.Character:FindFirstChild("Head") then 

									local HeadPos, HeadOnScreen = WTVP(Camera, Entity.Character.Head.CFrame.p); 
									local HeadPos2, HeadOnScreen2 = WTVP(Camera, Entity.Character.Head.CFrame.p + (Entity.Character.Head.CFrame.lookVector * 5));

									if HeadOnScreen2 and HeadOnScreen then 
										Entity.Components.LookAngle.Visible = true; 
										
										Visuals.RotateLine(Entity.Components.LookAngle, 1, Vector2.new(HeadPos.X, HeadPos.Y), Vector2.new(HeadPos2.X, HeadPos2.Y));
										Entity.Components.LookAngle.Color = ElementColor;
									else 
										Entity.Components.LookAngle.Visible = false
									end;
								else
									if Entity.Components.LookAngle then 
										Entity.Components.LookAngle.Visible = false
									end;
								end; 

								--// ESPSkeleton
								if ESPSkeletonFlag and Entity.Character:FindFirstChild("Head") then
								
									local Validated = true
									for _, PartName in ipairs(RequiredParts) do
										if not Entity.Character:FindFirstChild(PartName) then
											Validated = false
											break
										end
									end

									do --// Rendering
										if Validated then 
											local RL = WTVP(Camera, Entity.Character.RightUpperLeg.CFrame.p)
											local LL = WTVP(Camera, Entity.Character.LeftUpperLeg.CFrame.p)
								
											local Head = WTVP(Camera, Entity.Character.Head.CFrame.p)
								
											local RightLeg = WTVP(Camera, Entity.Character.RightUpperLeg.CFrame.p + Vector3.new(0, 0.5, 0))
											local LeftLeg = WTVP(Camera, Entity.Character.LeftUpperLeg.CFrame.p + Vector3.new(0, 0.5, 0))
								
											local RightFoot = WTVP(Camera, Entity.Character.RightFoot.CFrame.p)
											local LeftFoot = WTVP(Camera, Entity.Character.LeftFoot.CFrame.p)
								
											local RightArm = WTVP(Camera, Entity.Character.RightUpperArm.CFrame.p + Vector3.new(0, 0.2, 0))
											local LeftArm = WTVP(Camera, Entity.Character.LeftUpperArm.CFrame.p + Vector3.new(0, 0.2, 0))
								
											local RightElbow = WTVP(Camera, Entity.Character.RightLowerArm.CFrame.p + Vector3.new(0, 0.2, 0))
											local LeftElbow = WTVP(Camera, Entity.Character.LeftLowerArm.CFrame.p + Vector3.new(0, 0.2, 0))
								
											local RightHand = WTVP(Camera, Entity.Character.RightHand.CFrame.p)
											local LeftHand = WTVP(Camera, Entity.Character.LeftHand.CFrame.p)
								
											do  --// Properties
												for Index, Value in next, Skeleton do
													Value.Visible = true
													Value.Color = ElementColor
												end
								
												Visuals.RotateLine(Skeleton.RightFoot, 1, Vector2.new(RightFoot.X, RightFoot.Y), Vector2.new(RL.X, RL.Y))
												Visuals.RotateLine(Skeleton.LeftFoot, 1, Vector2.new(LeftFoot.X, LeftFoot.Y), Vector2.new(LL.X, LL.Y))
								
												Visuals.RotateLine(Skeleton.LL_line, 1, Vector2.new(LeftLeg.X, LeftLeg.Y), Vector2.new(LL.X, LL.Y))
												Visuals.RotateLine(Skeleton.RL_line, 1, Vector2.new(RightLeg.X, RightLeg.Y), Vector2.new(RL.X, RL.Y))
								
												Visuals.RotateLine(Skeleton.RightArm, 1, Vector2.new(RightArm.X, RightArm.Y), Vector2.new(RightElbow.X, RightElbow.Y))
												Visuals.RotateLine(Skeleton.RightElbow, 1, Vector2.new(RightElbow.X, RightElbow.Y), Vector2.new(RightHand.X, RightHand.Y))
								
												Visuals.RotateLine(Skeleton.LeftArm, 1, Vector2.new(LeftArm.X, LeftArm.Y), Vector2.new(LeftElbow.X, LeftElbow.Y))
												Visuals.RotateLine(Skeleton.LeftElbow, 1, Vector2.new(LeftElbow.X, LeftElbow.Y), Vector2.new(LeftHand.X, LeftHand.Y))
								
												Visuals.RotateLine(Skeleton.Main, 1, Vector2.new((LeftLeg.X + RightLeg.X) / 2 , LeftLeg.Y), Vector2.new(Head.X, Head.Y))
								
												Visuals.RotateLine(Skeleton.Hips, 1, Vector2.new(LeftLeg.X, LeftLeg.Y), Vector2.new(RightLeg.X, RightLeg.Y))
								
												Visuals.RotateLine(Skeleton.Shoulders, 1, Vector2.new(RightArm.X, RightArm.Y), Vector2.new(LeftArm.X, LeftArm.Y))
											end
										end
									end
								
									do --// R6
										if Entity.Character.Humanoid.RigType == Enum.HumanoidRigType.R6 then
											local Head = WTVP(Camera, Entity.Character.Head.CFrame.p)
									
											local Torso = WTVP(Camera, Entity.Character.Torso.CFrame.p)
											local Shoulders = WTVP(Camera, Entity.Character.Torso.CFrame.p + Vector3.new(0, Entity.Character.Torso.Size.Y / 2, 0))
											local Hips = WTVP(Camera, Entity.Character.Torso.CFrame.p - Vector3.new(0, Entity.Character.Torso.Size.Y / 2, 0))
											
											local RightArmHeight = Entity.Character["Right Arm"].Size.Y / 2 - 0.2
											local LeftArmHeight = Entity.Character["Left Arm"].Size.Y / 2 - 0.2

											--local RightShoulder = WTVP(Camera, Entity.Character["Right Arm"].CFrame.p + Vector3.new(0, Entity.Character.Torso.Size.Y * 0.3))
											--local LeftShoulder = WTVP(Camera, Entity.Character["Left Arm"].CFrame.p - Vector3.new(0, -Entity.Character.Torso.Size.Y * 0.3))
											--local RightShoulder = WTVP(Camera, Entity.Character.Torso.CFrame.p + Vector3.new((Entity.Character["Right Arm"].Size.X * 1.5), Entity.Character.Torso.Size.Y * 0.5, 0))
											--local LeftShoulder = WTVP(Camera, Entity.Character.Torso.CFrame.p - Vector3.new((Entity.Character["Left Arm"].Size.X * 1.5), -Entity.Character.Torso.Size.Y * 0.5, 0))
									
											local RightArm = WTVP(Camera, Entity.Character["Right Arm"].CFrame.p - Vector3.new(0, Entity.Character["Right Arm"].Size.Y / 2, 0))
											local RightHand = WTVP(Camera, (Entity.Character["Right Arm"].CFrame * CFrame.new(0, -RightArmHeight, 0)).p)

											local LeftArm = WTVP(Camera, Entity.Character["Left Arm"].CFrame.p - Vector3.new(0, Entity.Character["Left Arm"].Size.Y / 2, 0))
											local LeftHand = WTVP(Camera, (Entity.Character["Left Arm"].CFrame * CFrame.new(0, -LeftArmHeight, 0)).p)

											local RightLeg = WTVP(Camera, Entity.Character["Right Leg"].CFrame.p)
											local RightFoot = WTVP(Camera, Entity.Character["Right Leg"].CFrame.p - Vector3.new(0, Entity.Character["Right Leg"].Size.Y / 2, 0))
											local LeftLeg = WTVP(Camera, Entity.Character["Left Leg"].CFrame.p)
											local LeftFoot = WTVP(Camera, Entity.Character["Left Leg"].CFrame.p - Vector3.new(0, Entity.Character["Left Leg"].Size.Y / 2, 0))
									
											for Index, Value in next, Skeleton do
												Value.Visible = true
												Value.Color = ElementColor
											end
									
											Visuals.RotateLine(Skeleton.Main, 1, Vector2.new(Hips.X, Hips.Y), Vector2.new(Head.X, Head.Y))
											--Visuals.RotateLine(Skeleton.Shoulders, 1, Vector2.new(Torso.X, RightShoulder.Y), Vector2.new(LeftShoulder.X, LeftShoulder.Y))
											Visuals.RotateLine(Skeleton.RightArm, 1, Vector2.new(Shoulders.X, Shoulders.Y), Vector2.new(RightHand.X, RightHand.Y))
											Visuals.RotateLine(Skeleton.LeftArm, 1, Vector2.new(Shoulders.X, Shoulders.Y), Vector2.new(LeftHand.X, LeftHand.Y))
											Visuals.RotateLine(Skeleton.LL_line, 1, Vector2.new(Hips.X, Hips.Y), Vector2.new(LeftFoot.X, LeftFoot.Y))
											Visuals.RotateLine(Skeleton.RL_line, 1, Vector2.new(Hips.X, Hips.Y), Vector2.new(RightFoot.X, RightFoot.Y))
										-- Visuals.RotateLine(Skeleton.Hips, 1, Vector2.new(LeftLeg.X, Hips.Y), Vector2.new(RightLeg.X, Hips.Y))
										end
									end
								else 
									for Index, Value in next, Skeleton do 
										Value.Visible = false
									end
								end
								
								if HighlightFlag and Entity.IsPlayer then 
									Library.Tween(Highlight, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {FillColor = ElementColor})
									Library.Tween(Highlight, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {OutlineColor = ElementColor})
									--Highlight.FillColor = ElementColor; 
									Highlight.DepthMode = "AlwaysOnTop";
									--Highlight.OutlineColor = ElementColor; 
									Highlight.Adornee = Entity.Character; 
									Highlight.Enabled = true
									if PulseHighlights then 
										local x = 1 - math.sin(tick() * 4) 
										Highlight.FillTransparency = x 
										Highlight.OutlineTransparency = x; 

									else 
										Highlight.FillTransparency = 0.25;
										Highlight.OutlineTransparency = 0;

									end;
								else 
									Highlight.Enabled = false
								end;

							else
								for Index, Value in next, Skeleton do 
									Value.Visible = false;
								end;

								Entity.Components.LookAngle.Visible = false
								Entity.Components.BoxOutline.Visible = false
							end;
						end;
					else
						
						do --// Components Invisible
							for Index, Value in next, Skeleton do 
								Value.Visible = false;
							end;
							
							if not IsStudio then 
								Entity.Components.LookAngle.Visible = false
							end; 

							Entity.Components.BoxOutline.Visible = false
						end;

						do --// ESP Offscreen Arrows 
							if not Entity.LastUpdate then Entity.LastUpdate = tick() end;
							if Entity.IsPlayer and BoxData and ESPEnabled and Library.Flags[Class.."_OffscreenArrows"] and Library.Flags[Class.."_OffscreenArrows"].Value and BoxData.Root then 

								if tick() - Entity.LastUpdate > 0.02 then 
									Entity.LastUpdate = tick() 
									local ElementColor = BoxData.Visible and Library.Flags.ESPVisibleColor.Color or Library.Flags.ESPOccludedColor.Color;
									local Arrow = Components.OffscreenArrow;
									local RootPosition = BoxData.Root.CFrame.p;
									local CameraPosition = Camera.CFrame.p;
									local ViewAngle = Camera.CFrame.lookVector;
									
									local ScreenPos, OnScreen = WTSP(Camera, RootPosition)

									local Bounds = 0 

									local Center = Camera.ViewportSize / 2
									local Direction = (Vector2.new(ScreenPos.X, ScreenPos.Y) - Vector2.new(Center.X, Center.Y)).Unit
								
									local OffscreenRadius = Library.Flags[Class.."_ArrowRadius"].Value
									local ClampedPosition = Vector2.new(Center.X, Center.Y) + Direction * OffscreenRadius
									
									Arrow.Size = UDim2.new(0, Library.Flags[Class.."_ArrowWidth"].Value, 0, Library.Flags[Class.."_ArrowHeight"].Value);
									Arrow.Position = UDim2.new(0, ClampedPosition.X - Arrow.Size.X.Offset / 2, 0, ClampedPosition.Y - Arrow.Size.Y.Offset / 2)
									Arrow.Rotation = math.deg(math.atan2(Direction.Y, Direction.X)) + 90
									Arrow.ImageColor3 = ElementColor
									Arrow.Visible = true

									Arrow.Image = Images[Library.Flags[Class.."_ArrowStyle"].Value]
									
									local NameOffscreen = Components.NameOffscreen;
									local DistanceOffscreen = Components.DistanceOffscreen; 
									local WeaponOffscreen = Components.WeaponOffscreen; 
									local _, WeaponName = Entity:GetWeapon(); 

									local Height = Library.Flags[Class.."_ArrowHeight"].Value 
									local Width  = Library.Flags[Class.."_ArrowWidth"].Value 

									local PosY = (Arrow.Position.Y.Offset - Height) - 10 
									local PosX = (Arrow.Position.X.Offset) - 10

									NameOffscreen.ZIndex = BoxData.Visible and 20 or 1 
									Components.HealthbarOffscreen.ZIndex = BoxData.Visible and 20 or 1 
									WeaponOffscreen.ZIndex = BoxData.Visible and 20 or 1 
									DistanceOffscreen.ZIndex = BoxData.Visible and 20 or 1 
									Arrow.ZIndex = BoxData.Visible and 20 or 1

									if OffNameFlag then 
										NameOffscreen.Text = not Library.Flags.ShowDisplayName.Value and Entity.Name or Object.DisplayName; 
										NameOffscreen.Position = UDim2.new(0, PosX , 0, (PosY + Height) - 10);
										NameOffscreen.Visible = true
									else 
										NameOffscreen.Visible = false 
									end; 

									if OffDistanceFlag then 
										DistanceOffscreen.Text = tostring(math.floor((Camera.CFrame.p - BoxData.Root.CFrame.p).magnitude)).."s";
										DistanceOffscreen.Position = UDim2.new(0, PosX , 0, (PosY+ Height*2) + Bounds + 10)
										DistanceOffscreen.Visible = true

										Bounds+=12
									else 
										DistanceOffscreen.Visible = false 
									end;

									if OffWeaponFlag then 
										WeaponOffscreen.Text = WeaponName;
										WeaponOffscreen.Visible = true;
										WeaponOffscreen.Position = UDim2.new(0, PosX , 0, (PosY + (Height*2)) + Bounds + 10);
										Bounds+=12
									else 
										WeaponOffscreen.Visible = false 
									end;

									if OffHealthFlag then 
										Components.HealthbarOffscreen.Size = UDim2.new(0, 1, 0, Arrow.AbsoluteSize.Y - 5)
										Components.HealthbarOffscreen.Position = UDim2.new(0, PosX - 5, 0, PosY + Height + 15)
										Components.HealthbarOffscreen.Visible = true 

										local Health, MaxHealth = Entity:GetHealth()

										if not Entity.PreviousHealth then 
											Entity.PreviousHealth = 100;
										end;
		
										if tick() - Entity.LastUpdate > 0.3 then
											Entity.LastUpdate = tick();
											Entity.PreviousHealth = math.floor(Health)
											local LerpedColor = Library.Flags.HealthbarLower.Color:lerp(Library.Flags.HealthbarPositive.Color, Entity.PreviousHealth  / MaxHealth)

											Library.Tween(Components.HealthbarOffscreen, TweenInfo.new(0.3, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut), {BackgroundColor3 = LerpedColor})
											Library.Tween(Components.HealthbarInvertOffscreen, TweenInfo.new(0.3, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut), {Size = UDim2.new(1, 0, 1 - (Entity.PreviousHealth / MaxHealth), 0)});

											Components.HealthTextOffscreen.Text = Entity.PreviousHealth
										end

									else 
										Components.HealthbarOffscreen.Visible = false 
									end; 
								end;

							else 
								Components.NameOffscreen.Visible = false 
								Components.DistanceOffscreen.Visible = false
								Components.OffscreenArrow.Visible = false
								Components.WeaponOffscreen.Visible = false
								Components.HealthbarOffscreen.Visible = false
							end;
						end; 

						
					end
				end

				Aimbot.Target = ActualPlayer;
				Aimbot.TargetName = ActualPlayerName;
				Aimbot.TargetPart = ClosestTarget;

				if Visuals.TargetLine or IsStudio then 

					Visuals.FOVInline.BackgroundTransparency = Library.Flags.FOVColor.Transparency 
					
					if Library.Flags.DynamicFOV.Value then
						task.spawn(function()
							task.wait(0.01)
							local Difference = (OldFieldOfView / Camera.FieldOfView);
							local FOVRadius = Library.Flags.FOVRadius.Value;
	
							Visuals.FOVOutline.Size = UDim2.new(0, Difference * FOVRadius, 0, Difference * FOVRadius);
						end);

					else 
						Visuals.FOVOutline.Size = UDim2.new(0, Library.Flags["FOVRadius"].Value, 0, Library.Flags["FOVRadius"].Value)
					end;

					if ClosestTarget then 
						Aimbot.TargetPosition = ClosestTarget.CFrame.p;
						Aimbot.CurrentPosition = Camera.CFrame.p;

						if Library.Flags.EnableFOVLockColor.Value then 
							Library.Tween(Visuals.FOVStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Color = Library.Flags.LockColor.Color});
							Library.Tween(Visuals.FOVInline, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundColor3 = Library.Flags.LockColor.Color});
						end; 

						if Visuals.TargetLine then 
							if Library.Flags.TargetLine.Value then 
								local Pos, _ = WTVP(Camera, ClosestTarget.CFrame.p);
								Target2d = Pos;

								local Center = Vector2.new(Camera.ViewportSize.X / 2, Camera.ViewportSize.Y / 2)

								if Workspace:FindFirstChild("VFX") and Workspace.VFX:FindFirstChild("VMs")then
									local Viewmodels = Workspace.VFX.VMs:GetChildren()
					
									if #Viewmodels >= 1 then
										local VM = Viewmodels[1]
										local Weapon = VM and VM:FindFirstChild("Weapon") 
	
										local Barrel = Weapon and Weapon:FindFirstChild("FlashPart")
											
										if Barrel then 
											local Pos, _ = WTVP(Camera, Barrel.CFrame.p);
											Center = Vector2.new(Pos.X, Pos.Y);
										end;
									end
								end

								Visuals.TargetLine.Visible = true; 
								Visuals.TargetLine.From = Center;
								Visuals.TargetLine.To = Vector2.new(Target2d.X, Target2d.Y)
								Visuals.TargetLine.Color = Library.Flags.TargetLineColor.Color;

							else 
								Visuals.TargetLine.Visible = false;
							end;
						end;

						if Library.Flags.AimbotMethod.Value == "Mouse" and Library.Flags.AimbotKey.Value then
							local ScreenPosition, _ = WTSP(Camera, ClosestTarget.CFrame.p);
							mousemoverel((ScreenPosition.X - Mouse.X) / (Library.Flags.AimbotSmoothing.Value), (ScreenPosition.Y - Mouse.Y)  / (Library.Flags.AimbotSmoothing.Value))
						end;

						if Library.Flags.DisplayTargetInfo.Value and Aimbot.Target and Entities.List[Aimbot.Target] and Entities.List[Aimbot.Target].IsPlayer and Aimbot.Target.Character and Aimbot.Target.Character:FindFirstChild("Humanoid") then 
							local Armor = Entities.Functions:GetArmor(Aimbot.Target);
							local WeaponTable = Entities.Functions:GetAttachments(Aimbot.Target);
							if Armor then

								for i = 1, 7 do
									if not Armor[i] then
										Armor[i] = "None"
									end
								end

								Visuals.InfoFrame.Visible = true
								Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(0, 326, 0, 300)})
								Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 0})

								for Index, Value in next, Visuals.InfoFrame:GetDescendants() do 
									if Value.BackgroundColor3 ~= Color3.fromRGB(255, 255, 255) and Value.BackgroundColor3 ~= Color3.fromRGB(255, 0, 0) then 
										Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 0})
									end;

									if Value.ClassName == "TextLabel" then 
										Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 0})
									end;

									if Value.ClassName == "ImageLabel" then 
										Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageTransparency = 0})
									end;
								end;

								local TitleText = Aimbot.TargetName;
								local Text = "";

								for Index, Name in ipairs(Armor) do 
									Text = Text.. (string.format("<font color='rgb(200, 200, 200)'>[</font><font color='rgb(0, 229, 255)'>%s</font><font color='rgb(200, 200, 200)'>]</font>     <font color='rgb(255, 255, 255)'>%s</font>", tostring(Index), Name)).."\n\n"
								end;

								Library.UpdateInfoViewer(TitleText, Text, Aimbot.Target:GetAttribute("VIP"), tostring(math.floor(Aimbot.Target.Character.Humanoid.Health)), Armor, WeaponTable);


							else
								Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(0, 326, 0, 5)})
								Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
								for Index, Value in next, Visuals.InfoFrame:GetDescendants() do 
									Library.Tween(Value, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
									if Value.ClassName == "TextLabel" then 
										Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 1})
									end;

									if Value.ClassName == "ImageLabel" then 
										Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageTransparency = 1})
									end;
								end;
							end;
						else
							Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(0, 326, 0, 5)})
							Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
							for Index, Value in next, Visuals.InfoFrame:GetDescendants() do 
								if Value.BackgroundColor3 ~= Color3.fromRGB(255, 255, 255) and Value.BackgroundColor3 ~= Color3.fromRGB(255, 0, 0) then 
									Library.Tween(Value, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
								end;

								if Value.ClassName == "TextLabel" then 
									Library.Tween(Value, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 1})
								end;

								if Value.ClassName == "ImageLabel" then 
									Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageTransparency = 1})
								end;
							end;
						end;
					else
						Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Size = UDim2.new(0, 326, 0, 5)})
						Library.Tween(Visuals.InfoFrame, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
						
						for Index, Value in next, Visuals.InfoFrame:GetDescendants() do 
							if Value.BackgroundColor3 ~= Color3.fromRGB(255, 255, 255) and Value.BackgroundColor3 ~= Color3.fromRGB(255, 0, 0) then 
								Library.Tween(Value, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundTransparency = 1})
							end;

							if Value.ClassName == "TextLabel" then 
								Library.Tween(Value, TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {TextTransparency = 1})
							end;

							if Value.ClassName == "ImageLabel" then 
								Library.Tween(Value, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {ImageTransparency = 1})
							end;
						end;
						Library.Tween(Visuals.FOVStroke, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {Color = Library.Flags.FOVColor.Color});
						Library.Tween(Visuals.FOVInline, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {BackgroundColor3 = Library.Flags.FOVColor.Color});

						if Visuals.TargetLine then 
							Visuals.TargetLine.Visible = false;
						end;
					end;
				end;
			end;

			do --// Manipulation 
				if Aimbot.TargetPart and Library.Flags.SilentManipulation.Value and Library.Flags.ManipulationKey.Value then 
					local VisiblePosition = Utility.FindVisiblePosition(Camera.CFrame.p, Aimbot.TargetPart);
					if VisiblePosition then 
						Utility.ManipulatedPosition = VisiblePosition;
					else 
						Utility.ManipulatedPosition = nil;
					end
				else 
					Utility.ManipulatedPosition = nil;
				end;
			end;

			do --// Item Entities
				for Object, Entity in next, Items.List do
					if not Entity.Components then 
						Entity.Components = ESP:CreateItemComponents();
					end;

					if Library.Flags["ESP"..Entity.Class] and Library.Flags["ESP"..Entity.Class].Value and Library.Flags.MiscESPEnabled.Value and not Library.Flags.CombatHide.Value then 
						if Entity.Destroy then 
							Entity.Components.Name:Destroy() 
						end;

						local Root = (Entity.GetRoot and Entity:GetRoot());

						if Root then
							local Check = true; 
							if Entity.CustomCheck then 
								Check = Entity:CustomCheck();
							end;

							if Check then 
								local ScreenPosition, OnScreen = WTVP(Camera, Root.CFrame.p);

								if OnScreen then 
									local Name = Entity:GetCustomName(Entity);
									local Distance = math.floor((Camera.CFrame.p - Root.CFrame.p).Magnitude);
									Entity.Name = Name;

									local Components = Entity.Components;

									if Distance <= Library.Flags.ESPMiscDistance.Value then
										Components.Name.Position = UDim2.new(0, ScreenPosition.X, 0, ScreenPosition.Y);
										Components.Name.TextColor3 = Library.Flags[Entity.ColorListener].Color;
										Components.Name.Text = Name;
										Components.Distance.Text = tostring(Distance).."s";
										Components.Distance.Visible = Library.Flags.ShowMiscDistance.Value
										Components.Distance.TextColor3 = Library.Flags.DistanceColor.Color
										Components.Name.Visible = true;

										if Library.Flags.SmartESP.Value then 
											local FadeDistance = Library.Flags.FadeRadius.Value 
											local DistanceFromCenter = Utility.GetDistanceFromCenter(Root.CFrame.p)

											local FadeTransparency = math.clamp(DistanceFromCenter / FadeDistance, 0, 1)
											Components.Name.TextTransparency = FadeTransparency
											Components.Distance.TextTransparency = FadeTransparency

											Components.Name.stroke.Transparency = FadeTransparency 
											Components.Name.Distance.stroke.Transparency = FadeTransparency 
										else 
											Components.Name.TextTransparency = 0
											Components.Distance.TextTransparency = 0

											Components.Name.stroke.Transparency = 0 
											Components.Name.Distance.stroke.Transparency = 0 
										end
									else 
										Components.Name.Visible = false;
									end;
								else 
									Entity.Components.Name.Visible = false
								end;
							else 
								Entity.Components.Name.Visible = false 
								--Entity.Components.Distance.Visible = false
							end;

						else 
							Entity.Components.Name.Visible = false
						end;
					else
