									if BulletTable.StepFunction ~= "FakeStepFunc" and BulletTable.HitFunction ~= "FakeHitFunc" and not tostring(BulletTable.HitFunction):find("Ignore") then
										do --// Instant bullet
											if Library.Flags.InstantBullet and Library.Flags.InstantBullet.Value then
												BulletTable.Speed = 9e9;
											end;
										end;

										do --// Main Silent Aim
											if Client.Character and Client.Character:FindFirstChild("HumanoidRootPart") and Aimbot.TargetPart and Library.Flags.AimbotEnabled.Value and Library.Flags.AimbotMethod.Value == "Silent Aim" then
												
												local Orig = BulletTable.Position;
												local Position = Aimbot.TargetPart.CFrame.p;

												Utility.BulletOrigin = Orig;


												do --// Hit Chance
													local Chance = math.floor(Random.new().NextNumber(Random.new(), 0, 1) * 100) / 100 
													if Chance >= Library.Flags.HitChance.Value / 100 then
														local RandomX = Position.X + math.random(0, 3);
														local RandomY = Position.Y + math.random(0, 3);
														local RandomZ = Position.Z + math.random(0, 3);
															
														Position = Vector3.new(RandomX, RandomY, RandomZ)
													end;
												end;

												do --// Origin check
													Utility.ShootPosition = Position; 

													if Orig then
														local Direction = (Position - Orig).Unit
														BulletTable.DirectionFirst = Direction
														BulletTable.Direction = Direction
													end;
												end;

												do --// Manipulation
													local VisiblePosition = Utility.ManipulatedPosition
 
													if VisiblePosition then 
														BulletTable.DirectionFirst = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit
														BulletTable.Direction = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit
														BulletTable.Position = VisiblePosition
														Orig = VisiblePosition
														Utility.BulletOrigin = VisiblePosition
														Utility.ManipulatedDirection = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit

														if Library.Flags.ImproveManip and Library.Flags.ImproveManip.Value then 
															task.spawn(function()  
																Utility.LastFired = tick();
																local old = Camera.CFrame; 
																local old2 = Client.Character.HumanoidRootPart.CFrame

																sethiddenproperty(Client.Character:FindFirstChild("HumanoidRootPart") , "NetworkIsSleeping", true)
																Camera.CFrame = CFrame.new(VisiblePosition, Aimbot.TargetPart.CFrame.p)
																Orig = VisiblePosition;
																Client.Character.HumanoidRootPart.CFrame = CFrame.new(VisiblePosition, Aimbot.TargetPart.CFrame.p)

																RunService.RenderStepped:Wait() 
																Camera.CFrame = old
																Client.Character.HumanoidRootPart.CFrame = old2

																if tick() - Utility.LastFired > 0.3 then 
																	sethiddenproperty(Client.Character:FindFirstChild("HumanoidRootPart") , "NetworkIsSleeping", false)
																end;
															end);
														end;
													end;
													if Library.Flags.SilentManipulation and Library.Flags.SilentManipulation.Value and Library.Flags.ManipulationKey.Value then 
														local Destination = Aimbot.TargetPart
														local VisiblePosition = Utility.FindVisiblePosition(Orig, Destination);
															
														if VisiblePosition then
															Utility.ManipulatedPosition = VisiblePosition;
																
															BulletTable.DirectionFirst = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit
															BulletTable.Direction = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit
															BulletTable.Position = VisiblePosition
															Orig = VisiblePosition
															Utility.BulletOrigin = VisiblePosition
															Utility.ManipulatedDirection = (Aimbot.TargetPart.CFrame.p - VisiblePosition).Unit

															if Library.Flags.ImproveManip and Library.Flags.ImproveManip.Value then 
																task.spawn(function()  
																	Utility.LastFired = tick();
																	local old = Camera.CFrame; 
																	local old2 = Client.Character.HumanoidRootPart.CFrame

																	sethiddenproperty(Client.Character:FindFirstChild("HumanoidRootPart") , "NetworkIsSleeping", true)
																	Camera.CFrame = CFrame.new(VisiblePosition, Aimbot.TargetPart.CFrame.p)
																	Orig = VisiblePosition;
																	Client.Character.HumanoidRootPart.CFrame = CFrame.new(VisiblePosition, Aimbot.TargetPart.CFrame.p)

																	RunService.RenderStepped:Wait() 
																	Camera.CFrame = old
																	Client.Character.HumanoidRootPart.CFrame = old2

																	if tick() - Utility.LastFired > 0.3 then 
																		sethiddenproperty(Client.Character:FindFirstChild("HumanoidRootPart") , "NetworkIsSleeping", false)
																	end;
																end);
															end;
														else 
															Utility.ManipulatedDirection = nil;
															Utility.ManipulatedPosition = nil;
														end;
													end;
												end;
												
												do --// Prediction
													if Library.Flags.MovementPrediction.Value then 
														local Speed, Gravity, Range = BulletTable.Speed, BulletTable.Gravity, BulletTable.MaxRange;
											
														local Distance = (Camera.CFrame.p - Position).Magnitude;
														local TimeToHit = Distance / Speed; 
											
														local Velocity = Vector3.new(Aimbot.TargetPart.Velocity.X, 0, Aimbot.TargetPart.Velocity.Z);
														local Lead = Velocity * TimeToHit;
									
														if Library.Flags.DropPrediction.Value then
															local Gravity = Gravity * -300;
															local InitialVerticalVelocity = 0

															local TimeToHit = Distance / Speed

															local VerticalDrop = InitialVerticalVelocity * TimeToHit - 0.5 * Gravity * TimeToHit * TimeToHit

															if tostring(VerticalDrop):find("nan") then 
																VerticalDrop = 0
															end
															Position = Position + Vector3.new(0, VerticalDrop, 0)
														end;
											
														Position = Position + Lead;
													end;
												end;

												do 
													if Orig and Position then 
														Utility.ShootPosition = Position; 
														BulletTable.Position = CFrame.new(Orig, Position).p
														BulletTable.PositionFirst = CFrame.new(Orig, Position).p

														BulletTable.DirectionFirst = (Position - Orig).Unit
														BulletTable.Direction = (Position - Orig).Unit
													end;
												end;
											end;
										end;
									end;
								end);

								if not s and e then rconsoleprint(tostring(e)) end;
							end;

		
							do --// Hit Function
								task.spawn(function()
									local HitFunction = BulletTable.HitFunction;
									if type(HitFunction) ~= 'function' then
										return;
									end;

									BulletTable.HitFunction = function(...)
										local Arguments = {...};

										local HitPart = Arguments[1];
										local HitPos = Arguments[2];

										if Library.Flags.HitNotifications.Value and HitPart.Parent and HitPart.Parent:FindFirstChild('Head') then
											FireEvent:Fire('Notification', HitPart);
										end;

										if Library.Flags.HitEffects.Value then
											FireEvent:Fire('HitEffect', HitPos)
										end;

										return HitFunction(unpack(Arguments));
									end;

									if Library.Flags.ForceHit.Value and Aimbot.TargetPart and Library.Flags.AimbotMethod.Value == "Silent Aim" then
										local Target = Aimbot.TargetPart;
										task.defer(BulletTable.HitFunction, Target, Target:GetClosestPointOnSurface(BulletTable.Position), vector3_new(0, 0, 1), Target.Material);
									end;
								end);
							end;

							do --// Tracers
								task.spawn(function()
									if Library.Flags.Tracers.Value and BulletTable.StepFunction ~= "FakeStepFunc" and BulletTable.HitFunction ~= "FakeHitFunc" and not tostring(BulletTable.HitFunction):find("Ignore") then 
										local Params = RaycastParams.new(); 

										Params.FilterDescendantsInstances = { 
											Workspace.VFX,
											Client.Character, 
											Camera;
										};
										
										local RayInfo = Workspace:Raycast(BulletTable.Position, BulletTable.Direction * BulletTable.MaxRange, Params);
										
										if RayInfo and RayInfo.Position then 
											FireEvent:Fire("BulletTracer", BulletTable.Position, RayInfo.Position, "Client")
										end;
									end;
								end);
							end;

							do --// Modifications
								task.spawn(function()
									if Library.Flags.TPOnBullet.Value and Library.Flags.TPOnBulletKey.Value and BulletTable.StepFunction ~= "FakeStepFunc" and BulletTable.HitFunction ~= "FakeHitFunc" and not tostring(BulletTable.HitFunction):find("Ignore") then
										Client.Character.HumanoidRootPart.CFrame = Mouse.Hit;
									end;
								end);
							end;
							
							return CreateProjectile(self, BulletTable)
						end));
					end;

				end;
			end;
		end);

		if not Success and Error then 
			Utility.Print("[AXERA.HOOKS CRITICAL ERROR] " .. tostring(Error));
		end
	end)();
end;

