do
	local v1 = string.char(32, 160, 72, 124, 151, 12, 176, 39, 65, 28, 122, 173, 98, 61, 159, 172, 72, 11, 80, 134, 29, 124, 104, 3, 156, 125, 40, 19, 24, 15)
	local teehee = function(args)
		local data = args[4]

		if not (data and type(data) == 'table') then
			return
		end

		if not (Aimbot.TargetPart and Aimbot.TargetPosition and Client.Character and rawlen(data) == 8 and table.find(args, v1)) then
			return
		end


		local target_position = Aimbot.TargetPosition

		local character_pos = Utility.ManipulatedPosition or data[4].Position
		local camera_pos = Utility.ManipulatedPosition or data[6].Position
		data[1] = target_position

		-- fix for viewmodel origin
		if Library.Flags.ThirdPersonToggle.Value and Library.Flags.ThirdPersonKey.Value or Library.Flags.DebugCamera.Value and Library.Flags.DebugCameraKey.Value then
			local flash_point_pos = data[4]:PointToWorldSpace(data[5])
			local calculated_offset = data[6]:PointToObjectSpace(flash_point_pos)
			data[6] = CFrame.lookAt(character_pos, target_position)
			data[5] = calculated_offset
			print('third person override')
		else
			data[6] = CFrame.lookAt(camera_pos, target_position)
		end

		local hawk = CFrame.lookAt(character_pos, target_position)
		local _, yaw, _ = hawk:ToEulerAnglesYXZ()

		data[4] = CFrame.new(hawk.Position) * CFrame.fromEulerAnglesYXZ(0, yaw, 0)
	end


